import React from 'react';
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from 'recharts';
import styles from './DepartmentComparisonChart.module.css';

interface DepartmentData {
  department: string;
  visits: number;
  employees: number;
  referrals: number;
  preamtiveCheckUps?: number;
  annualCheckup?: number;
}

interface DepartmentComparisonChartProps {
  data: DepartmentData[];
  dataKey?: 'visits' | 'referrals' | 'preamtiveCheckUps' | 'annualCheckup';
  titleLabel?: string;
  color?: string;
  sortBy?: 'department' | 'visits' | 'referrals' | 'preamtiveCheckUps' | 'annualCheckup';
  sortOrder?: 'asc' | 'desc';
  loading?: boolean;
  height?: number;
}

/**
 * DepartmentComparisonChart component
 * Horizontal bar chart comparing visits across departments
 */
export const DepartmentComparisonChart: React.FC<DepartmentComparisonChartProps> = ({
  data,
  dataKey = 'visits',
  titleLabel = 'Visits',
  color = '#3b82f6',
  sortBy = 'visits',
  sortOrder = 'desc',
  loading = false,
  height = 400,
}) => {
  // Sort data
  const sortedData = React.useMemo(() => {
    const sorted = [...data].sort((a, b) => {
      const aValue = sortBy === 'department' ? a.department : (a[sortBy] ?? 0);
      const bValue = sortBy === 'department' ? b.department : (b[sortBy] ?? 0);
      const comparison = aValue > bValue ? 1 : aValue < bValue ? -1 : 0;
      return sortOrder === 'asc' ? comparison : -comparison;
    });
    return sorted;
  }, [data, sortBy, sortOrder]);

  // Custom tooltip
  const CustomTooltip = ({ active, payload }: any) => {
    if (active && payload && payload.length) {
      const data = payload[0].payload;
      return (
        <div className={styles.tooltip}>
          <p className={styles.tooltipTitle}>{data.department}</p>
          <p className={styles.tooltipRow}>
            <span className={styles.tooltipLabel}>{titleLabel}:</span>
            <span className={styles.tooltipValue}>{data[dataKey] ?? 0}</span>
          </p>
          <p className={styles.tooltipRow}>
            <span className={styles.tooltipLabel}>Employees:</span>
            <span className={styles.tooltipValue}>{data.employees}</span>
          </p>
          <p className={styles.tooltipRow}>
            <span className={styles.tooltipLabel}>Referrals:</span>
            <span className={styles.tooltipValue}>{data.referrals}</span>
          </p>
        </div>
      );
    }
    return null;
  };

  if (loading) {
    return <div className={styles.skeleton} style={{ height }} />;
  }

  if (sortedData.length === 0) {
    return (
      <div className={styles.empty} style={{ height }}>
        <p>No data available</p>
      </div>
    );
  }

  return (
    <div className={styles.chart} style={{ height }}>
      <ResponsiveContainer width="100%" height="100%">
        <BarChart
          data={sortedData}
          layout="vertical"
          margin={{ top: 5, right: 30, left: 100, bottom: 5 }}
        >
          <CartesianGrid strokeDasharray="3 3" stroke="#e5e7eb" />
          <XAxis type="number" stroke="#6b7280" fontSize={12} tickLine={false} axisLine={false} />
          <YAxis
            type="category"
            dataKey="department"
            stroke="#6b7280"
            fontSize={12}
            tickLine={false}
            axisLine={false}
            width={90}
          />
          <Tooltip content={<CustomTooltip />} />
          <Legend />
          <Bar
            dataKey={dataKey}
            fill={color}
            name={titleLabel}
            radius={[0, 4, 4, 0]}
            animationDuration={500}
          />
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
};

import React from 'react';
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from 'recharts';
import styles from './DiagnosisAreaChart.module.css';

interface DiagnosisData {
  diagnosis: string;
  data: Array<{ date: Date; count: number }>;
  color: string;
  severity?: string;
}

interface DiagnosisAreaChartProps {
  data: DiagnosisData[];
  loading?: boolean;
  showLegend?: boolean;
  height?: number;
}

const DIAGNOSIS_COLORS = [
  '#3b82f6', // Blue
  '#10b981', // Green
  '#f59e0b', // Yellow
  '#ef4444', // Red
  '#8b5cf6', // Purple
];

/**
 * DiagnosisAreaChart component
 * Area chart showing diagnosis volume over time
 */
export const DiagnosisAreaChart: React.FC<DiagnosisAreaChartProps> = ({
  data,
  loading = false,
  showLegend = true,
  height = 400,
}) => {
  // Transform data for Recharts
  const chartData = React.useMemo(() => {
    if (data.length === 0) return [];

    // Get all unique dates
    const allDates = new Set<string>();
    data.forEach((diagnosis) => {
      diagnosis.data.forEach((point) => {
        allDates.add(point.date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }));
      });
    });

    // Create data points for each date
    const sortedDates = Array.from(allDates).sort((a, b) => {
      const dateA = new Date(a);
      const dateB = new Date(b);
      return dateA.getTime() - dateB.getTime();
    });

    return sortedDates.map((date) => {
      const point: any = { date };
      data.forEach((diagnosis) => {
        const dataPoint = diagnosis.data.find(
          (d) => d.date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }) === date
        );
        point[diagnosis.diagnosis] = dataPoint?.count || 0;
      });
      return point;
    });
  }, [data]);

  // Assign colors if not provided
  const coloredData = data.map((item, index) => ({
    ...item,
    color: item.color || DIAGNOSIS_COLORS[index % DIAGNOSIS_COLORS.length],
  }));

  // Custom tooltip
  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className={styles.tooltip}>
          <p className={styles.tooltipDate}>{label}</p>
          {payload.map((entry: any, index: number) => (
            <p key={index} className={styles.tooltipRow}>
              <span className={styles.tooltipLabel} style={{ color: entry.color }}>
                {entry.dataKey}:
              </span>
              <span className={styles.tooltipValue}>{entry.value} cases</span>
            </p>
          ))}
        </div>
      );
    }
    return null;
  };

  if (loading) {
    return <div className={styles.skeleton} style={{ height }} />;
  }

  if (chartData.length === 0) {
    return (
      <div className={styles.empty} style={{ height }}>
        <p>No data available</p>
      </div>
    );
  }

  return (
    <div className={styles.chart} style={{ height }}>
      <ResponsiveContainer width="100%" height="100%">
        <AreaChart data={chartData} margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>
          <CartesianGrid strokeDasharray="3 3" stroke="#e5e7eb" />
          <XAxis
            dataKey="date"
            stroke="#6b7280"
            fontSize={12}
            tickLine={false}
            axisLine={false}
          />
          <YAxis
            stroke="#6b7280"
            fontSize={12}
            tickLine={false}
            axisLine={false}
          />
          <Tooltip content={<CustomTooltip />} />
          {showLegend && <Legend />}
          {coloredData.map((diagnosis) => (
            <Area
              key={diagnosis.diagnosis}
              type="monotone"
              dataKey={diagnosis.diagnosis}
              stroke={diagnosis.color}
              fill={diagnosis.color}
              fillOpacity={0.3}
              strokeWidth={2}
              name={diagnosis.diagnosis}
              animationDuration={500}
            />
          ))}
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
};

