import React from 'react';
import styles from './HealthIndexGauge.module.css';

interface HealthIndexData {
  department: string;
  healthIndex: number;
  visits: number;
  referrals: number;
  unfit: number;
  employees: number;
}

interface HealthIndexGaugeProps {
  data: HealthIndexData;
  size?: number;
  showLabel?: boolean;
  animate?: boolean;
}

/**
 * HealthIndexGauge component
 * Custom gauge/meter showing health index (0-100%)
 */
export const HealthIndexGauge: React.FC<HealthIndexGaugeProps> = ({
  data,
  size = 180,
  showLabel = true,
  animate = true,
}) => {
  const [animatedIndex, setAnimatedIndex] = React.useState(0);

  React.useEffect(() => {
    if (animate && typeof performance !== 'undefined' && typeof requestAnimationFrame !== 'undefined') {
      const duration = 1000;
      const start = 0;
      const end = data.healthIndex;
      const startTime = performance.now();

      const animateValue = (currentTime: number) => {
        const elapsed = currentTime - startTime;
        const progress = Math.min(elapsed / duration, 1);

        // Easing function
        const easeOutQuart = 1 - Math.pow(1 - progress, 4);
        setAnimatedIndex(start + (end - start) * easeOutQuart);

        if (progress < 1) {
          requestAnimationFrame(animateValue);
        }
      };

      requestAnimationFrame(animateValue);
    } else {
      setAnimatedIndex(data.healthIndex);
    }
  }, [data.healthIndex, animate]);

  // Determine color based on health index
  const getColor = (index: number) => {
    if (index >= 80) return '#10b981'; // Green
    if (index >= 60) return '#f59e0b'; // Yellow
    return '#ef4444'; // Red
  };

  const color = getColor(animatedIndex);
  const radius = (size - 20) / 2;
  const circumference = 2 * Math.PI * radius;
  const offset = circumference - (animatedIndex / 100) * circumference;

  return (
    <div className={styles.gaugeContainer} style={{ width: size, height: size }}>
      <svg width={size} height={size} className={styles.gauge}>
        {/* Background circle */}
        <circle
          cx={size / 2}
          cy={size / 2}
          r={radius}
          fill="none"
          stroke="#e5e7eb"
          strokeWidth={12}
        />

        {/* Progress circle */}
        <circle
          cx={size / 2}
          cy={size / 2}
          r={radius}
          fill="none"
          stroke={color}
          strokeWidth={12}
          strokeLinecap="round"
          strokeDasharray={circumference}
          strokeDashoffset={offset}
          transform={`rotate(-90 ${size / 2} ${size / 2})`}
          className={styles.progressCircle}
        />

        {/* Center text */}
        <text x="50%" y="50%" dominantBaseline="middle" textAnchor="middle" className={styles.centerText}>
          <tspan x="50%" dy="-0.3em" className={styles.percentage}>
            {Math.round(animatedIndex)}%
          </tspan>
          {showLabel && (
            <tspan x="50%" dy="1.2em" className={styles.label}>
              Health
            </tspan>
          )}
        </text>
      </svg>

      {/* Tooltip with details */}
      <div className={styles.tooltip}>
        <p className={styles.tooltipTitle}>{data.department}</p>
        <div className={styles.tooltipDetails}>
          <div className={styles.tooltipRow}>
            <span className={styles.tooltipLabel}>Employees:</span>
            <span className={styles.tooltipValue}>{data.employees}</span>
          </div>
          <div className={styles.tooltipRow}>
            <span className={styles.tooltipLabel}>Visits:</span>
            <span className={styles.tooltipValue}>{data.visits}</span>
          </div>
          <div className={styles.tooltipRow}>
            <span className={styles.tooltipLabel}>Referrals:</span>
            <span className={styles.tooltipValue}>{data.referrals}</span>
          </div>
          <div className={styles.tooltipRow}>
            <span className={styles.tooltipLabel}>Unfit:</span>
            <span className={styles.tooltipValue}>{data.unfit}</span>
          </div>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import {
  PieChart,
  Pie,
  Cell,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from 'recharts';
import styles from './SeverityPieChart.module.css';

interface SeverityData {
  severity: 'MILD' | 'MODERATE' | 'SEVERE' | 'CRITICAL';
  count: number;
  color: string;
  percentage?: number;
}

interface SeverityPieChartProps {
  data: SeverityData[];
  loading?: boolean;
  showTotal?: boolean;
  height?: number;
}

const SEVERITY_COLORS: Record<string, string> = {
  MILD: '#10b981',
  MODERATE: '#f59e0b',
  SEVERE: '#f97316',
  CRITICAL: '#ef4444',
};

/**
 * SeverityPieChart component
 * Donut/pie chart showing disease severity breakdown
 */
export const SeverityPieChart: React.FC<SeverityPieChartProps> = ({
  data,
  loading = false,
  showTotal = true,
  height = 400,
}) => {
  // Calculate total
  const total = data.reduce((sum, item) => sum + item.count, 0);

  // Prepare chart data with colors
  const chartData = data.map((item) => ({
    name: item.severity,
    value: item.count,
    color: item.color || SEVERITY_COLORS[item.severity],
    percentage: total > 0 ? ((item.count / total) * 100).toFixed(1) : 0,
  }));

  // Custom tooltip
  const CustomTooltip = ({ active, payload }: any) => {
    if (active && payload && payload.length) {
      const data = payload[0].payload;
      return (
        <div className={styles.tooltip}>
          <p className={styles.tooltipSeverity}>{data.name}</p>
          <p className={styles.tooltipRow}>
            <span className={styles.tooltipLabel}>Count:</span>
            <span className={styles.tooltipValue}>{data.value}</span>
          </p>
          <p className={styles.tooltipRow}>
            <span className={styles.tooltipLabel}>Percentage:</span>
            <span className={styles.tooltipValue}>{data.percentage}%</span>
          </p>
        </div>
      );
    }
    return null;
  };

  // Custom label for center of donut
  const renderCenterText = () => {
    if (!showTotal) return null;
    return (
      <div className={styles.centerText}>
        <p className={styles.centerLabel}>Total</p>
        <p className={styles.centerValue}>{total}</p>
      </div>
    );
  };

  if (loading) {
    return <div className={styles.skeleton} style={{ height }} />;
  }

  if (chartData.length === 0) {
    return (
      <div className={styles.empty} style={{ height }}>
        <p>No data available</p>
      </div>
    );
  }

  return (
    <div className={styles.chart} style={{ height }}>
      <ResponsiveContainer width="100%" height="100%">
        <PieChart>
          <Pie
            data={chartData}
            cx="50%"
            cy="50%"
            innerRadius={60}
            outerRadius={80}
            paddingAngle={2}
            dataKey="value"
            label={({
              cx,
              cy,
              midAngle,
              innerRadius,
              outerRadius,
              percent,
            }: any) => {
              const RADIAN = Math.PI / 180;
              const radius = innerRadius + (outerRadius - innerRadius) * 0.5;
              const x = cx + radius * Math.cos(-midAngle * RADIAN);
              const y = cy + radius * Math.sin(-midAngle * RADIAN);

              if (percent < 0.05) return null; // Don't show label for small slices

              return (
                <text
                  x={x}
                  y={y}
                  fill="white"
                  textAnchor={x > cx ? 'start' : 'end'}
                  dominantBaseline="central"
                  fontSize={12}
                  fontWeight={500}
                >
                  {`${(percent * 100).toFixed(0)}%`}
                </text>
              );
            }}
            animationDuration={500}
          >
            {chartData.map((entry, index) => (
              <Cell key={`cell-${index}`} fill={entry.color} />
            ))}
          </Pie>
          <Tooltip content={<CustomTooltip />} />
          <Legend />
        </PieChart>
        {renderCenterText()}
      </ResponsiveContainer>
    </div>
  );
};

import React from 'react';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from 'recharts';
import styles from './SeverityTrendChart.module.css';

interface SeverityData {
  severity: string;
  data: Array<{ date: Date; count: number }>;
  color: string;
}

interface SeverityTrendChartProps {
  data: SeverityData[];
  loading?: boolean;
  showLegend?: boolean;
  height?: number;
}

const SEVERITY_COLORS: Record<string, string> = {
  MILD: '#10b981',
  MODERATE: '#f59e0b',
  SEVERE: '#f97316',
  CRITICAL: '#ef4444',
};

/**
 * SeverityTrendChart component
 * Line chart showing severity distribution trends over time
 */
export const SeverityTrendChart: React.FC<SeverityTrendChartProps> = ({
  data,
  loading = false,
  showLegend = true,
  height = 400,
}) => {
  // Transform data for Recharts
  const chartData = React.useMemo(() => {
    if (data.length === 0) return [];

    // Get all unique dates
    const allDates = new Set<string>();
    data.forEach((severity) => {
      severity.data.forEach((point) => {
        allDates.add(point.date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }));
      });
    });

    // Create data points for each date
    const sortedDates = Array.from(allDates).sort((a, b) => {
      const dateA = new Date(a);
      const dateB = new Date(b);
      return dateA.getTime() - dateB.getTime();
    });

    return sortedDates.map((date) => {
      const point: any = { date };
      data.forEach((severity) => {
        const dataPoint = severity.data.find(
          (d) => d.date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }) === date
        );
        point[severity.severity] = dataPoint?.count || 0;
      });
      return point;
    });
  }, [data]);

  // Assign colors if not provided
  const coloredData = data.map((item) => ({
    ...item,
    color: item.color || SEVERITY_COLORS[item.severity] || '#6b7280',
  }));

  // Custom tooltip
  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className={styles.tooltip}>
          <p className={styles.tooltipDate}>{label}</p>
          {payload.map((entry: any, index: number) => (
            <p key={index} className={styles.tooltipRow}>
              <span className={styles.tooltipLabel} style={{ color: entry.color }}>
                {entry.dataKey}:
              </span>
              <span className={styles.tooltipValue}>{entry.value} cases</span>
            </p>
          ))}
        </div>
      );
    }
    return null;
  };

  if (loading) {
    return <div className={styles.skeleton} style={{ height }} />;
  }

  if (chartData.length === 0) {
    return (
      <div className={styles.empty} style={{ height }}>
        <p>No data available</p>
      </div>
    );
  }

  return (
    <div className={styles.chart} style={{ height }}>
      <ResponsiveContainer width="100%" height="100%">
        <LineChart data={chartData} margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>
          <CartesianGrid strokeDasharray="3 3" stroke="#e5e7eb" />
          <XAxis
            dataKey="date"
            stroke="#6b7280"
            fontSize={12}
            tickLine={false}
            axisLine={false}
          />
          <YAxis
            stroke="#6b7280"
            fontSize={12}
            tickLine={false}
            axisLine={false}
          />
          <Tooltip content={<CustomTooltip />} />
          {showLegend && <Legend />}
          {coloredData.map((severity) => (
            <Line
              key={severity.severity}
              type="monotone"
              dataKey={severity.severity}
              stroke={severity.color}
              strokeWidth={2}
              dot={{ fill: severity.color, strokeWidth: 2, r: 3 }}
              activeDot={{ r: 5 }}
              name={severity.severity}
              animationDuration={500}
            />
          ))}
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
};

