import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { useSnackbar } from '../../contexts/SnackbarContext';
import { Header } from '../layout';
import { Alert, Button } from '../ui';
import { RefreshControl } from '../charts';
import api, { handleApiError } from '../../services/api';
import { Role, VisitStatus, VisitType } from '../../types';
import styles from './PreEmploymentDoctorDashboard.module.css';

interface AnnualHealthVisit {
  id: number;
  employee?: {
    employee_code: string;
    department?: string;
    user?: { first_name?: string; last_name?: string };
  } | null;
  employee_name?: string;
  employee_id?: string;
  employee_department?: string;
  patient_name?: string;
  patient_age?: number;
  patient_gender?: string;
  visit_date: string;
  visit_time?: string;
  visit_status: VisitStatus;
}

export const AnnualHealthDoctorDashboard: React.FC = () => {
  const navigate = useNavigate();
  const { user } = useAuth();
  const { show } = useSnackbar();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [selectedFilter, setSelectedFilter] = useState<string>(VisitStatus.OPEN);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [visits, setVisits] = useState<AnnualHealthVisit[]>([]);

  const handleError = useCallback((err: unknown) => {
    const message = handleApiError(err, 'Failed to fetch annual health checkups');
    setError(message);
    show(message, 'error');
  }, [show]);

  const fetchVisits = useCallback(async () => {
    try {
      setLoading(true);
      const params = new URLSearchParams();
      if (selectedFilter) params.append('visit_status', selectedFilter);
      params.append('visit_type', VisitType.PERIODIC);

      const response = await api.get(`/ohc/visits/?${params.toString()}`);
      const visitsData = response.data.results || response.data || [];
      setVisits(Array.isArray(visitsData) ? visitsData : []);
      setLastUpdated(new Date());
      setError('');
    } catch (err) {
      handleError(err);
    } finally {
      setLoading(false);
    }
  }, [handleError, selectedFilter]);

  useEffect(() => {
    if (!user || user.role !== Role.DOCTOR) {
      navigate('/dashboard');
      return;
    }
    void fetchVisits();
  }, [fetchVisits, navigate, user]);

  const stats = useMemo(() => ({
    total: visits.length,
    open: visits.filter((visit) => visit.visit_status === VisitStatus.OPEN).length,
    completed: visits.filter((visit) => visit.visit_status === VisitStatus.COMPLETED).length,
  }), [visits]);

  const getDisplayName = (visit: AnnualHealthVisit) =>
    visit.patient_name ||
    visit.employee_name ||
    `${visit.employee?.user?.first_name || ''} ${visit.employee?.user?.last_name || ''}`.trim() ||
    'N/A';

  const getDisplayCode = (visit: AnnualHealthVisit) => visit.employee_id || visit.employee?.employee_code || 'N/A';
  const getDisplayDepartment = (visit: AnnualHealthVisit) => visit.employee_department || visit.employee?.department || 'N/A';

  return (
    <div className={styles.dashboard}>
      <Header title="Annual Health Checkup - Doctor" subtitle="Review and diagnose annual health checkups" />

      <main className={styles.dashboardMain}>
        {error && <Alert type="danger" onDismiss={() => setError('')}>{error}</Alert>}

        <div className={styles.cardHeader}>
          <h2>Doctor Queue</h2>
          <RefreshControl onRefresh={() => void fetchVisits()} isRefreshing={loading} lastUpdated={lastUpdated ?? undefined} />
        </div>

        <div className={styles.filterTabs}>
          <button type="button" className={`${styles.filterTab} ${selectedFilter === VisitStatus.OPEN ? styles.active : ''}`} onClick={() => setSelectedFilter(VisitStatus.OPEN)}>
            Open
          </button>
          <button type="button" className={`${styles.filterTab} ${selectedFilter === VisitStatus.IN_PROGRESS ? styles.active : ''}`} onClick={() => setSelectedFilter(VisitStatus.IN_PROGRESS)}>
            In Progress
          </button>
          <button type="button" className={`${styles.filterTab} ${selectedFilter === VisitStatus.COMPLETED ? styles.active : ''}`} onClick={() => setSelectedFilter(VisitStatus.COMPLETED)}>
            Completed
          </button>
        </div>

        <div className={styles.visitDetails}>
          <div className={styles.detailItem}>
            <span className={styles.detailLabel}>Total</span>
            <span>{stats.total}</span>
          </div>
          <div className={styles.detailItem}>
            <span className={styles.detailLabel}>Open</span>
            <span>{stats.open}</span>
          </div>
          <div className={styles.detailItem}>
            <span className={styles.detailLabel}>Completed</span>
            <span>{stats.completed}</span>
          </div>
        </div>

        {loading ? (
          <div className={styles.loading}>Loading annual health checkups...</div>
        ) : visits.length === 0 ? (
          <div className={styles.emptyState}>No annual health checkups found</div>
        ) : (
          <div className={styles.visitsList}>
            {visits.map((visit) => (
              <div key={visit.id} className={styles.visitCard}>
                <div className={styles.visitHeader}>
                  <div className={styles.visitInfo}>
                    <h3>{getDisplayName(visit)}</h3>
                    <p className={styles.employeeCode}>{getDisplayCode(visit)}</p>
                    <p className={styles.department}>{getDisplayDepartment(visit)}</p>
                  </div>
                  <span>{visit.visit_status}</span>
                </div>

                <div className={styles.visitDetails}>
                  <div className={styles.detailItem}>
                    <span className={styles.detailLabel}>Date</span>
                    <span>{new Date(visit.visit_date).toLocaleDateString()}</span>
                  </div>
                  <div className={styles.detailItem}>
                    <span className={styles.detailLabel}>Time</span>
                    <span>{visit.visit_time ? new Date(`2000-01-01T${visit.visit_time}`).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : '-'}</span>
                  </div>
                  <div className={styles.detailItem}>
                    <span className={styles.detailLabel}>Gender</span>
                    <span>{visit.patient_gender || '-'}</span>
                  </div>
                  <div className={styles.detailItem}>
                    <span className={styles.detailLabel}>Age</span>
                    <span>{visit.patient_age ? `${visit.patient_age} yrs` : '-'}</span>
                  </div>
                </div>

                <div className={styles.detailActions}>
                  <Button type="button" variant="brand" onClick={() => navigate(`/annual-health-doctor/request/${visit.id}`)}>
                    View Request
                  </Button>
                </div>
              </div>
            ))}
          </div>
        )}
      </main>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { useSnackbar } from '../../contexts/SnackbarContext';
import { Header } from '../layout';
import { Alert, Button, Card, FormInput } from '../ui';
import api, { handleApiError } from '../../services/api';
import { listHospitals } from '../../services/ahc';
import { listMedicines } from '../../services/medicine';
import { FitnessDecision, Role, VisitType, type Hospital } from '../../types';
import { FITNESS_DECISION_OPTIONS } from '../../utils/constants';
import { validatePrescription } from '../../utils/errorHandling';
import { loadMedicineRecords } from './medicineInventory';
import pageStyles from './RequestPage.module.css';
import dashboardStyles from './PreEmploymentDoctorDashboard.module.css';

interface PrescriptionInput {
  medicine_name: string;
  dosage: string;
  frequency: string;
  duration_days: number;
  instructions?: string;
}

const FITNESS_STATUS_OPTIONS = [
  { value: '', label: 'Select fitness status' },
  ...FITNESS_DECISION_OPTIONS,
];

export const AnnualHealthDoctorRequestPage: React.FC = () => {
  const navigate = useNavigate();
  const { visitId } = useParams<{ visitId: string }>();
  const { user } = useAuth();
  const { show } = useSnackbar();

  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');
  const [fieldErrors, setFieldErrors] = useState<Record<string, string>>({});
  const [selectedVisit, setSelectedVisit] = useState<any | null>(null);
  const [medicines, setMedicines] = useState<Array<{ value: string; label: string }>>([]);
  const [diagnosisName, setDiagnosisName] = useState('');
  const [examinationNotes, setExaminationNotes] = useState('');
  const [followUpDate, setFollowUpDate] = useState('');
  const [fitnessDecision, setFitnessDecision] = useState<FitnessDecision | ''>('');
  const [requiresReferral, setRequiresReferral] = useState(false);
  const [selectedHospitalId, setSelectedHospitalId] = useState('');
  const [medicineRequired, setMedicineRequired] = useState(false);
  const [hospitalOptions, setHospitalOptions] = useState<Array<{ value: string; label: string }>>([
    { value: '', label: 'Select hospital' },
  ]);
  const [prescriptions, setPrescriptions] = useState<PrescriptionInput[]>([
    { medicine_name: '', dosage: '', frequency: '', duration_days: 7, instructions: '' },
  ]);

  useEffect(() => {
    if (!user || user.role !== Role.DOCTOR) {
      navigate('/dashboard');
    }
  }, [navigate, user]);

  useEffect(() => {
    const fetchVisit = async () => {
      if (!visitId) {
        navigate('/annual-health-doctor', { replace: true });
        return;
      }

      try {
        setLoading(true);
        const response = await api.get(`/ohc/visits/${visitId}/`);
        if (response.data?.visit_type !== VisitType.PERIODIC) {
          setError('Annual health checkup details were not found');
          return;
        }
        setSelectedVisit(response.data);
      } catch (err) {
        const message = err instanceof Error ? err.message : 'Failed to load annual health checkup';
        setError(message);
        show(message, 'error');
      } finally {
        setLoading(false);
      }
    };

    void fetchVisit();
  }, [navigate, show, visitId]);

  useEffect(() => {
    const fetchHospitals = async () => {
      try {
        const response = await listHospitals({ status: 'ACTIVE', page_size: 100 });
        const hospitals = (response.results || []) as Hospital[];
        setHospitalOptions([
          { value: '', label: 'Select hospital' },
          ...hospitals.map((hospital) => ({
            value: String(hospital.id),
            label: hospital.name,
          })),
        ]);
      } catch {
        setHospitalOptions([{ value: '', label: 'Select hospital' }]);
      }
    };

    void fetchHospitals();
  }, []);

  useEffect(() => {
    const fetchMedicines = async () => {
      try {
        const localMedicineNames = Array.from(
          new Set<string>(
            loadMedicineRecords()
              .filter((medicine) => medicine.stock > 0)
              .map((medicine) => String(medicine.name || '').trim())
              .filter(Boolean),
          ),
        ).sort((left, right) => left.localeCompare(right));

        if (localMedicineNames.length > 0) {
          setMedicines([
            { value: '', label: 'Select medicine' },
            ...localMedicineNames.map((name) => ({ value: name, label: name })),
          ]);
          return;
        }

        const response = await listMedicines({ page_size: 500 });
        const medicineNames = Array.from(
          new Set<string>(
            (response.results || [])
              .filter((item: any) => item.stock_quantity > 0)
              .map((item: any) => String(item.name || '').trim())
              .filter(Boolean),
          ),
        ).sort((left, right) => left.localeCompare(right));

        setMedicines([
          { value: '', label: 'Select medicine' },
          ...medicineNames.map((name) => ({ value: name, label: name })),
        ]);
      } catch {
        setMedicines([{ value: '', label: 'Select medicine' }]);
      }
    };

    void fetchMedicines();
  }, []);

  const formatDate = (value?: string) => {
    if (!value) return '-';
    const date = new Date(value);
    return Number.isNaN(date.getTime()) ? value : date.toLocaleDateString();
  };

  const formatTime = (value?: string) => {
    if (!value) return '-';
    const time = new Date(`2000-01-01T${value}`);
    return Number.isNaN(time.getTime()) ? value : time.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const getTodayDateString = () => {
    const today = new Date();
    const year = today.getFullYear();
    const month = String(today.getMonth() + 1).padStart(2, '0');
    const day = String(today.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  };

  const getTomorrowDateString = () => {
    const tomorrow = new Date();
    tomorrow.setDate(tomorrow.getDate() + 1);
    const year = tomorrow.getFullYear();
    const month = String(tomorrow.getMonth() + 1).padStart(2, '0');
    const day = String(tomorrow.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  };

  const handleAddPrescription = () => {
    setPrescriptions((prev) => [
      ...prev,
      { medicine_name: '', dosage: '', frequency: '', duration_days: 7, instructions: '' },
    ]);
  };

  const handleRemovePrescription = (index: number) => {
    if (prescriptions.length > 1) {
      setPrescriptions((prev) => prev.filter((_, i) => i !== index));
    }
  };

  const handlePrescriptionChange = (index: number, field: keyof PrescriptionInput, value: string | number) => {
    setPrescriptions((prev) =>
      prev.map((item, itemIndex) => (itemIndex === index ? { ...item, [field]: value } : item)),
    );
    setFieldErrors((prev) => ({ ...prev, [`prescription_${index}_${field}`]: '' }));
  };

  const handleSubmitDiagnosis = async () => {
    if (!selectedVisit) return;

    setFieldErrors({});
    setError('');

    if (!diagnosisName.trim()) {
      setFieldErrors({ diagnosisName: 'Diagnosis is required' });
      show('Please enter diagnosis', 'error');
      return;
    }

    if (requiresReferral && !selectedHospitalId) {
      setFieldErrors({ selectedHospitalId: 'Please select hospital' });
      show('Please select a hospital for the referral', 'error');
      return;
    }

    if (!fitnessDecision) {
      setFieldErrors({ fitnessDecision: 'Please select fitness status' });
      show('Please select fitness status', 'error');
      return;
    }

    if (medicineRequired) {
      const filledPrescriptions = prescriptions.filter((item) => item.medicine_name.trim() !== '');
      if (filledPrescriptions.length === 0) {
        setFieldErrors({ prescriptions: 'At least one medicine is required when medicine is marked as required' });
        show('Please add at least one medicine or uncheck "Medicine Required"', 'error');
        return;
      }

      const prescriptionErrors: Record<string, string> = {};
      for (let i = 0; i < prescriptions.length; i += 1) {
        const item = prescriptions[i];
        if (!item.medicine_name.trim()) {
          continue;
        }

        const validation = validatePrescription(item);
        if (!validation.isValid) {
          validation.errors.forEach((fieldError) => {
            prescriptionErrors[`prescription_${i}_${fieldError.field}`] = fieldError.message;
          });
        }
      }

      if (Object.keys(prescriptionErrors).length > 0) {
        setFieldErrors(prescriptionErrors);
        show('Please correct the medicine details before submitting', 'error');
        return;
      }
    }

    if (followUpDate && followUpDate <= getTodayDateString()) {
      setFieldErrors({ followUpDate: 'Follow-up date must be after today' });
      show('Please select a follow-up date after today', 'error');
      return;
    }

    try {
      setSubmitting(true);
      const validPrescriptions = prescriptions.filter((item) => item.medicine_name.trim() !== '');
      await api.post('/ohc/diagnosis-prescriptions/', {
        visit: selectedVisit.id,
        diagnosis_code: '',
        diagnosis_name: diagnosisName,
        diagnosis_notes: examinationNotes || '',
        examination_notes: examinationNotes || '',
        severity: 'MILD' as const,
        is_primary: true,
        is_referral_required: requiresReferral,
        hospital: requiresReferral ? Number(selectedHospitalId) : undefined,
        condition_status: 'ACTIVE' as const,
        fitness_decision: fitnessDecision,
        work_restrictions: '',
        advised_rest_days: 0,
        follow_up_date: followUpDate || null,
        prescriptions: medicineRequired
          ? validPrescriptions.map((item) => ({
              ...item,
              start_date: new Date().toISOString().split('T')[0],
            }))
          : [],
      });
      show('Diagnosis created successfully!', 'success');
      navigate('/annual-health-doctor');
    } catch (err) {
      const message = handleApiError(err, 'Failed to create diagnosis');
      setError(message);
      show(message, 'error');
    } finally {
      setSubmitting(false);
    }
  };

  if (loading) {
    return (
      <div className={pageStyles.page}>
      <Header title="Annual Health Checkup Doctor Request" subtitle="Loading checkup details" />
        <div className={dashboardStyles.loading}>Loading visit details...</div>
      </div>
    );
  }

  if (!selectedVisit) {
    return (
      <div className={pageStyles.page}>
      <Header title="Annual Health Checkup Doctor Request" subtitle="Checkup details" />
        <main className={pageStyles.main}>
          {error && <Alert type="danger" onDismiss={() => setError('')}>{error}</Alert>}
        </main>
      </div>
    );
  }

  const displayName =
    selectedVisit.patient_name ||
    `${selectedVisit.employee?.user?.first_name || ''} ${selectedVisit.employee?.user?.last_name || ''}`.trim() ||
    'N/A';
  const displayCode = selectedVisit.employee_id || selectedVisit.employee?.employee_code || 'N/A';
  const displayDepartment = selectedVisit.employee_department || selectedVisit.employee?.department || 'N/A';

  return (
    <div className={pageStyles.page}>
      <Header title="Annual Health Checkup Doctor Request" subtitle="Review and diagnose annual health checkups" />

      <main className={pageStyles.main}>
        {error && <Alert type="danger" onDismiss={() => setError('')}>{error}</Alert>}

        <section className={pageStyles.hero}>
          <div className={pageStyles.heroText}>
            <span className={pageStyles.eyebrow}>Annual Health Checkup Doctor</span>
            <h2 className={pageStyles.heroTitle}>Checkup Details</h2>
            <p className={pageStyles.heroSubtitle}>
              Review employee information, vitals, and complete the annual health checkup diagnosis workflow.
            </p>
          </div>
          <div className={pageStyles.heroActions}>
            <span className={pageStyles.statusPill}>{selectedVisit.visit_status}</span>
            <Button type="button" variant="outline-secondary" onClick={() => navigate('/annual-health-doctor')}>
              Back
            </Button>
          </div>
        </section>

        <section className={pageStyles.summaryGrid}>
          <div className={pageStyles.summaryCard}>
            <span className={pageStyles.summaryLabel}>Employee</span>
            <span className={pageStyles.summaryValue}>{displayName}</span>
          </div>
          <div className={pageStyles.summaryCard}>
            <span className={pageStyles.summaryLabel}>Employee ID</span>
            <span className={pageStyles.summaryValue}>{displayCode}</span>
          </div>
          <div className={pageStyles.summaryCard}>
            <span className={pageStyles.summaryLabel}>Department</span>
            <span className={pageStyles.summaryValue}>{displayDepartment}</span>
          </div>
          <div className={pageStyles.summaryCard}>
            <span className={pageStyles.summaryLabel}>Visit Date</span>
            <span className={pageStyles.summaryValue}>{formatDate(selectedVisit.visit_date)}</span>
          </div>
        </section>

        <div className={pageStyles.contentGrid}>
          <div className={pageStyles.stack}>
            <Card className={pageStyles.panel}>
              <div className={pageStyles.panelHeader}>
                <div>
                  <h3 className={pageStyles.panelTitle}>Visit Overview</h3>
                  <p className={pageStyles.panelSubtitle}>Core annual health checkup details.</p>
                </div>
              </div>

              <div className={pageStyles.detailGrid}>
                <div className={pageStyles.detailItem}>
                  <span className={pageStyles.detailLabel}>Visit Time</span>
                  <span className={pageStyles.detailValue}>{formatTime(selectedVisit.visit_time)}</span>
                </div>
                <div className={pageStyles.detailItem}>
                  <span className={pageStyles.detailLabel}>Gender</span>
                  <span className={pageStyles.detailValue}>{selectedVisit.patient_gender || '-'}</span>
                </div>
                <div className={pageStyles.detailItem}>
                  <span className={pageStyles.detailLabel}>Age</span>
                  <span className={pageStyles.detailValue}>{selectedVisit.patient_age || '-'}</span>
                </div>
                <div className={pageStyles.detailItem}>
                  <span className={pageStyles.detailLabel}>Contact</span>
                  <span className={pageStyles.detailValue}>{selectedVisit.patient_contact || '-'}</span>
                </div>
              </div>
            </Card>

            {selectedVisit.vitals && Object.keys(selectedVisit.vitals).length > 0 && (
              <Card className={pageStyles.panel}>
                <div className={pageStyles.panelHeader}>
                  <div>
                    <h3 className={pageStyles.panelTitle}>Vital Signs</h3>
                    <p className={pageStyles.panelSubtitle}>Recorded measurements for this annual health checkup.</p>
                  </div>
                </div>

                <div className={pageStyles.vitalsGrid}>
                  {Object.entries(selectedVisit.vitals).map(([key, value]) => (
                    <div key={key} className={pageStyles.vitalCard}>
                      <span className={pageStyles.vitalName}>{key}</span>
                      <span className={pageStyles.vitalReading}>{String(value || '-')}</span>
                    </div>
                  ))}
                </div>
              </Card>
            )}
          </div>

          <div className={pageStyles.stack}>
            <Card className={pageStyles.panel}>
              <div className={pageStyles.panelHeader}>
                <div>
                  <h3 className={pageStyles.panelTitle}>Doctor Decision</h3>
                  <p className={pageStyles.panelSubtitle}>Complete diagnosis and send medicines to pharmacy when needed.</p>
                </div>
              </div>

              <div className={pageStyles.formStack}>
                <FormInput label="Diagnosis *" type="text" value={diagnosisName} onChange={setDiagnosisName} error={fieldErrors.diagnosisName} required />
                <FormInput label="Examination Notes" type="textarea" value={examinationNotes} onChange={setExaminationNotes} rows={4} />
                <FormInput
                  label="Fitness Status *"
                  type="select"
                  value={fitnessDecision}
                  onChange={(value) => setFitnessDecision(value as FitnessDecision)}
                  options={FITNESS_STATUS_OPTIONS}
                  error={fieldErrors.fitnessDecision}
                  required
                />
                <FormInput label="Follow-Up Date" type="date" value={followUpDate} onChange={setFollowUpDate} min={getTomorrowDateString()} error={fieldErrors.followUpDate} />
                <label className={pageStyles.checkboxRow}>
                  <input
                    type="checkbox"
                    checked={requiresReferral}
                    onChange={(event) => {
                      const checked = event.target.checked;
                      setRequiresReferral(checked);
                      setFieldErrors((prev) => ({ ...prev, selectedHospitalId: '' }));
                      if (!checked) {
                        setSelectedHospitalId('');
                      }
                    }}
                  />
                  <span>Referral required</span>
                </label>
                {requiresReferral && (
                  <FormInput
                    label="Hospital Name *"
                    type="select"
                    value={selectedHospitalId}
                    onChange={(value) => {
                      setSelectedHospitalId(value);
                      setFieldErrors((prev) => ({ ...prev, selectedHospitalId: '' }));
                    }}
                    options={hospitalOptions}
                    required
                    error={fieldErrors.selectedHospitalId}
                  />
                )}
              </div>
            </Card>

            <Card className={pageStyles.panel}>
              <div className={pageStyles.panelHeader}>
                <div>
                  <h3 className={pageStyles.panelTitle}>Pharmacy Handoff</h3>
                  <p className={pageStyles.panelSubtitle}>Add medicines if this annual health checkup needs pharmacist action.</p>
                </div>
              </div>

              <label className={pageStyles.checkboxRow}>
                <input type="checkbox" checked={medicineRequired} onChange={(event) => setMedicineRequired(event.target.checked)} />
                <span>Medicine Required</span>
              </label>

              {medicineRequired && (
                <div className={pageStyles.formStack}>
                  {prescriptions.map((prescription, index) => (
                    <div key={index} className={pageStyles.prescriptionRow}>
                      <div className={pageStyles.prescriptionTop}>
                        <span className={pageStyles.prescriptionIndex}>Medicine {index + 1}</span>
                        {prescriptions.length > 1 && (
                          <Button type="button" variant="outline-secondary" onClick={() => handleRemovePrescription(index)}>
                            Remove
                          </Button>
                        )}
                      </div>

                      <div className={pageStyles.prescriptionFormGrid}>
                        <FormInput
                          label="Medicine *"
                          type="select"
                          value={prescription.medicine_name}
                          onChange={(value) => handlePrescriptionChange(index, 'medicine_name', value)}
                          options={medicines}
                          error={fieldErrors[`prescription_${index}_medicine_name`]}
                          required
                        />
                        <FormInput
                          label="Dosage"
                          type="text"
                          value={prescription.dosage}
                          onChange={(value) => handlePrescriptionChange(index, 'dosage', value)}
                          error={fieldErrors[`prescription_${index}_dosage`]}
                        />
                        <FormInput
                          label="Frequency *"
                          type="text"
                          value={prescription.frequency}
                          onChange={(value) => handlePrescriptionChange(index, 'frequency', value)}
                          error={fieldErrors[`prescription_${index}_frequency`]}
                          required
                        />
                        <FormInput
                          label="Duration (Days) *"
                          type="number"
                          value={String(prescription.duration_days)}
                          onChange={(value) => handlePrescriptionChange(index, 'duration_days', Number(value))}
                          error={fieldErrors[`prescription_${index}_duration_days`]}
                          required
                        />
                        <div className={pageStyles.fullWidth}>
                          <FormInput
                            label="Instructions"
                            type="textarea"
                            value={prescription.instructions || ''}
                            onChange={(value) => handlePrescriptionChange(index, 'instructions', value)}
                            rows={2}
                          />
                        </div>
                      </div>
                    </div>
                  ))}

                  <div className={pageStyles.actionRow}>
                    <Button type="button" variant="outline-secondary" onClick={handleAddPrescription}>
                      Add Medicine
                    </Button>
                  </div>
                </div>
              )}
            </Card>

            <div className={pageStyles.actionRow}>
              <Button type="button" variant="outline-secondary" onClick={() => navigate('/annual-health-doctor')}>
                Cancel
              </Button>
              <Button type="button" variant="brand" onClick={handleSubmitDiagnosis} loading={submitting}>
                {requiresReferral ? 'Submit Referral' : 'Submit'}
              </Button>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

import React, { useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { useSnackbar } from '../../contexts/SnackbarContext';
import { Header } from '../layout';
import { Alert } from '../ui';
import { getPharmacistPrescriptions } from '../../services/ohc';
import { handleApiError } from '../../services/api';
import { Role, VisitType } from '../../types';
import styles from './PharmacistDashboard.module.css';

interface PrescriptionItem {
  id: number;
  visit: {
    employee?: {
      user: { first_name: string; last_name: string };
      employee_code: string;
    } | null;
    employee_id?: string;
    patient_name?: string;
    visit_date: string;
    visit_time?: string;
    visit_type?: string;
  };
  medicine_name: string;
  dosage: string;
  frequency: string;
  duration_days: number;
  is_dispensed?: boolean;
  medicine?: any;
}

export const AnnualHealthPharmacistDashboard: React.FC = () => {
  const navigate = useNavigate();
  const { user } = useAuth();
  const { show } = useSnackbar();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [prescriptions, setPrescriptions] = useState<PrescriptionItem[]>([]);

  useEffect(() => {
    if (!user || user.role !== Role.PHARMACIST) {
      navigate('/dashboard');
      return;
    }

    const fetchPrescriptions = async () => {
      try {
        setLoading(true);
        const data = await getPharmacistPrescriptions();
        setPrescriptions((data || []).filter((item: PrescriptionItem) => item.visit?.visit_type === VisitType.PERIODIC));
      } catch (err) {
        const message = handleApiError(err, 'Failed to fetch annual health checkup prescriptions');
        setError(message);
        show(message, 'error');
      } finally {
        setLoading(false);
      }
    };

    void fetchPrescriptions();
  }, [navigate, show, user]);

  const pendingCount = useMemo(() => prescriptions.filter((item) => !item.is_dispensed).length, [prescriptions]);
  const getDisplayName = (prescription: PrescriptionItem) =>
    prescription.visit.patient_name ||
    `${prescription.visit.employee?.user.first_name || ''} ${prescription.visit.employee?.user.last_name || ''}`.trim() ||
    'N/A';
  const getDisplayCode = (prescription: PrescriptionItem) =>
    prescription.visit.employee_id || prescription.visit.employee?.employee_code || 'N/A';

  return (
    <div className={styles.pharmacistDashboard}>
      <Header title="Annual Health Checkup Pharmacist" subtitle="Manage medicine requests for annual health checkups" />

      <main className={styles.dashboardMain}>
        {error && <Alert type="danger" onDismiss={() => setError('')}>{error}</Alert>}

        <div className={styles.inventoryStats}>
          <div className={styles.statCard}>
            <h4>Total Requests</h4>
            <p>{prescriptions.length}</p>
          </div>
          <div className={styles.statCard}>
            <h4>Pending Requests</h4>
            <p>{pendingCount}</p>
          </div>
          <div className={styles.statCard}>
            <h4>Dispensed Requests</h4>
            <p>{prescriptions.length - pendingCount}</p>
          </div>
        </div>

        <div className={styles.prescriptionsTab}>
          <h3>Annual Health Checkup Medicine Queue</h3>

          {loading ? (
            <div className={styles.loadingState}>Loading prescriptions...</div>
          ) : prescriptions.length === 0 ? (
            <div className={styles.emptyState}>
              <p>No annual health checkup prescriptions to process</p>
            </div>
          ) : (
            <div className={styles.prescriptionsList}>
              {prescriptions.map((prescription) => (
                <div
                  key={prescription.id}
                  className={`${styles.prescriptionListItem} ${prescription.is_dispensed ? styles.dispensedItem : ''}`}
                  onClick={() => !prescription.is_dispensed && prescription.medicine && navigate(`/annual-health-pharmacist/request/${prescription.id}`)}
                >
                  <div className={styles.listItemMain}>
                    <div className={styles.listItemPatient}>
                      <span className={styles.patientName}>{getDisplayName(prescription)}</span>
                      <span className={styles.employeeCode}>{getDisplayCode(prescription)}</span>
                    </div>
                    <div className={styles.listItemDate}>
                      <span>{new Date(prescription.visit.visit_date).toLocaleDateString()}</span>
                      {prescription.visit.visit_time && (
                        <span> {new Date(`2000-01-01T${prescription.visit.visit_time}`).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                      )}
                    </div>
                  </div>

                  <div className={styles.listItemMedicine}>
                    <span className={styles.medicineName}>{prescription.medicine_name}</span>
                    <span className={styles.medicineDetails}>
                      {prescription.dosage || '-'} | {prescription.frequency} | {prescription.duration_days}d
                    </span>
                  </div>

                  <div className={styles.listItemStatus}>
                    {prescription.is_dispensed ? (
                      <span className={styles.statusBadgeDispensed}>Dispensed</span>
                    ) : (
                      <span className={styles.statusBadgePending}>Pending</span>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Header } from '../layout';
import { Card, Button, Loading } from '../ui';
import { useAuth } from '../../contexts/AuthContext';
import api, { handleApiError } from '../../services/api';
import { getDashboard, getEHSStatistics, getMedicineSummary } from '../../services/analytics';
import { listMedicines } from '../../services/medicine';
import {
  ChartContainer,
  DashboardMetricsChart,
  DiagnosisTrendLineChart,
  OperationalBarChart,
} from '../charts';
import styles from './Dashboard.module.css';

type DashboardVisit = {
  id: number;
  employee?: {
    employee_code?: string;
    department?: string;
    user?: { first_name?: string; last_name?: string };
  };
  visit_type?: string;
  visit_status?: string;
  triage_level?: string;
  visit_date?: string;
  chief_complaint?: string;
  follow_up_date?: string | null;
  requires_referral?: boolean;
  prescriptions?: Array<{ id: number }>;
};

type SummaryTrendPoint = {
  period: string;
  ohcVisits: number;
  preamtiveCheckUps: number;
  annualCheckup: number;
  referralCases: number;
  emergencyCount: number;
  incidentCount: number;
};

type TrendGranularity = 'daily' | 'monthly' | 'yearly';

type MetricKey =
  | 'ohcVisits'
  | 'preamtiveCheckUps'
  | 'annualCheckup'
  | 'referralCases'
  | 'emergencyCount'
  | 'incidentCount';

type DepartmentPoint = {
  department: string;
  visits: number;
  employees: number;
  referrals: number;
  preamtiveCheckUps: number;
  annualCheckup: number;
};

type DepartmentMetricKey = 'visits' | 'preamtiveCheckUps' | 'annualCheckup';

type DiagnosisTrendPoint = {
  diagnosis: string;
  color: string;
  data: Array<{ date: Date; count: number }>;
};

type ActivityItem = {
  title: string;
  description: string;
  time: string;
  tag: string;
};

type OperationalBarPoint = {
  label: string;
  value: number;
};

type ChartState = {
  summaryTrends: Record<TrendGranularity, SummaryTrendPoint[]>;
  departmentComparison: DepartmentPoint[];
  diagnosisTrends: DiagnosisTrendPoint[];
  medicineUsageBreakdown: OperationalBarPoint[];
  bioWasteBreakdown: OperationalBarPoint[];
};

type MedicineInventoryItem = {
  name: string;
  used_quantity?: number;
};

const INCIDENT_KEYWORDS = [
  'injury', 'accident', 'cut', 'burn', 'fall', 'machine',
  'equipment', 'crush', 'puncture', 'fracture', 'sprain',
  'strain', 'work', 'occupational',
];

const EMERGENCY_KEYWORDS = [
  'heart attack', 'unconscious', 'fainted', 'seizure',
  'stroke', 'breathing difficulty', 'chest pain',
  'severe pain', 'emergency', 'collapse',
];

const DIAGNOSIS_COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6'];

const emptyCharts: ChartState = {
  summaryTrends: {
    daily: [],
    monthly: [],
    yearly: [],
  },
  departmentComparison: [],
  diagnosisTrends: [],
  medicineUsageBreakdown: [],
  bioWasteBreakdown: [],
};

const formatRelativeTime = (dateValue?: string) => {
  if (!dateValue) {
    return 'Recently';
  }

  const timestamp = new Date(dateValue).getTime();
  if (Number.isNaN(timestamp)) {
    return 'Recently';
  }

  const diffMs = Date.now() - timestamp;
  const diffHours = Math.max(1, Math.floor(diffMs / (1000 * 60 * 60)));
  if (diffHours < 24) {
    return `${diffHours} hour${diffHours === 1 ? '' : 's'} ago`;
  }

  const diffDays = Math.floor(diffHours / 24);
  return `${diffDays} day${diffDays === 1 ? '' : 's'} ago`;
};

const matchesKeywords = (text: string | undefined, keywords: string[]) => {
  const value = (text || '').toLowerCase();
  return keywords.some((keyword) => value.includes(keyword));
};

const isEmergencyVisit = (visit: DashboardVisit) =>
  visit.visit_type === 'EMERGENCY' || matchesKeywords(visit.chief_complaint, EMERGENCY_KEYWORDS);

const isIncidentVisit = (visit: DashboardVisit) =>
  visit.visit_type !== 'EMERGENCY' && matchesKeywords(visit.chief_complaint, INCIDENT_KEYWORDS);

const isPreEmploymentVisit = (visit: DashboardVisit) => visit.visit_type === 'PRE_EMPLOYMENT';

const isAnnualHealthCheckupVisit = (visit: DashboardVisit) => visit.visit_type === 'PERIODIC';

const isCoreOHCVisit = (visit: DashboardVisit) =>
  !isPreEmploymentVisit(visit) && !isAnnualHealthCheckupVisit(visit);

const isWithinGranularity = (visitDateValue: string | undefined, granularity: TrendGranularity) => {
  if (!visitDateValue) {
    return false;
  }

  const visitDate = new Date(visitDateValue);
  if (Number.isNaN(visitDate.getTime())) {
    return false;
  }

  const now = new Date();

  if (granularity === 'daily') {
    return (
      visitDate.getFullYear() === now.getFullYear() &&
      visitDate.getMonth() === now.getMonth() &&
      visitDate.getDate() === now.getDate()
    );
  }

  if (granularity === 'monthly') {
    return (
      visitDate.getFullYear() === now.getFullYear() &&
      visitDate.getMonth() === now.getMonth()
    );
  }

  return visitDate.getFullYear() === now.getFullYear();
};

const fetchAllVisits = async (): Promise<DashboardVisit[]> => {
  const visits: DashboardVisit[] = [];
  let page = 1;
  let hasNext = true;

  while (hasNext && page <= 25) {
    const response = await api.get('/ohc/visits/', {
      params: { page, page_size: 200, ordering: '-visit_date' },
    });
    const payload = response.data;
    const batch = Array.isArray(payload) ? payload : payload?.results || [];
    visits.push(...batch);
    hasNext = !Array.isArray(payload) && Boolean(payload?.next);
    page += 1;
  }

  return visits;
};

const buildSummaryTrends = (visits: DashboardVisit[], granularity: TrendGranularity) => {
  const trendMap = new Map<string, SummaryTrendPoint & { sortKey: number }>();
  const bucketLimit = granularity === 'daily' ? 7 : granularity === 'monthly' ? 6 : 5;

  visits.forEach((visit) => {
    if (!visit.visit_date) {
      return;
    }

    const visitDate = new Date(visit.visit_date);
    if (Number.isNaN(visitDate.getTime())) {
      return;
    }

    const year = visitDate.getFullYear();
    const month = visitDate.getMonth();
    const day = visitDate.getDate();

    let bucketKey = `${year}`;
    let period = `${year}`;
    let sortKey = year;

    if (granularity === 'daily') {
      bucketKey = `${year}-${month}-${day}`;
      period = visitDate.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
      sortKey = new Date(year, month, day).getTime();
    } else if (granularity === 'monthly') {
      bucketKey = `${year}-${month}`;
      period = visitDate.toLocaleDateString('en-US', { month: 'short' });
      sortKey = year * 100 + month;
    }

    if (!trendMap.has(bucketKey)) {
      trendMap.set(bucketKey, {
        period,
        sortKey,
        ohcVisits: 0,
        preamtiveCheckUps: 0,
        annualCheckup: 0,
        referralCases: 0,
        emergencyCount: 0,
        incidentCount: 0,
      });
    }

    const bucket = trendMap.get(bucketKey)!;
    if (isCoreOHCVisit(visit)) {
      bucket.ohcVisits += 1;
    }

    if (isPreEmploymentVisit(visit)) {
      bucket.preamtiveCheckUps += 1;
    }

    if (isAnnualHealthCheckupVisit(visit)) {
      bucket.annualCheckup += 1;
    }

    if (visit.requires_referral || visit.visit_status === 'REFERRED') {
      bucket.referralCases += 1;
    }

    if (isEmergencyVisit(visit)) {
      bucket.emergencyCount += 1;
    }

    if (isIncidentVisit(visit)) {
      bucket.incidentCount += 1;
    }
  });

  return Array.from(trendMap.values())
    .sort((a, b) => a.sortKey - b.sortKey)
    .slice(-bucketLimit)
    .map(({ sortKey: _sortKey, ...item }) => item);
};

const buildDepartmentComparison = (visits: DashboardVisit[]) => {
  const departmentMap = new Map<
    string,
    DepartmentPoint & { employeeCodes: Set<string> }
  >();

  visits.forEach((visit) => {
    const department = visit.employee?.department || 'Unknown';
    const employeeCode = visit.employee?.employee_code || '';

    if (!departmentMap.has(department)) {
      departmentMap.set(department, {
        department,
        visits: 0,
        employees: 0,
        referrals: 0,
        preamtiveCheckUps: 0,
        annualCheckup: 0,
        employeeCodes: new Set<string>(),
      });
    }

    const bucket = departmentMap.get(department)!;
    if (isCoreOHCVisit(visit)) {
      bucket.visits += 1;
    }
    if (employeeCode) {
      bucket.employeeCodes.add(employeeCode);
      bucket.employees = bucket.employeeCodes.size;
    }
    if (visit.requires_referral || visit.visit_status === 'REFERRED') {
      bucket.referrals += 1;
    }
    if (isPreEmploymentVisit(visit)) {
      bucket.preamtiveCheckUps += 1;
    }
    if (isAnnualHealthCheckupVisit(visit)) {
      bucket.annualCheckup += 1;
    }
  });

  return Array.from(departmentMap.values())
    .map(({ employeeCodes: _codes, ...item }) => item)
    .sort((a, b) => b.visits - a.visits);
};

const buildDiagnosisTrends = (visits: DashboardVisit[]) => {
  const complaintCounts = new Map<string, number>();

  visits.forEach((visit) => {
    const complaint = (visit.chief_complaint || '').trim();
    if (!complaint) {
      return;
    }
    complaintCounts.set(complaint, (complaintCounts.get(complaint) || 0) + 1);
  });

  const topComplaints = Array.from(complaintCounts.entries())
    .sort((a, b) => b[1] - a[1])
    .slice(0, 3)
    .map(([complaint]) => complaint);

  const monthlyMap = new Map<string, Map<string, number>>();
  const monthDates = new Map<string, Date>();

  visits.forEach((visit) => {
    const complaint = (visit.chief_complaint || '').trim();
    if (!topComplaints.includes(complaint) || !visit.visit_date) {
      return;
    }

    const visitDate = new Date(visit.visit_date);
    if (Number.isNaN(visitDate.getTime())) {
      return;
    }

    const monthKey = `${visitDate.getFullYear()}-${visitDate.getMonth()}`;
    if (!monthlyMap.has(monthKey)) {
      monthlyMap.set(monthKey, new Map<string, number>());
      monthDates.set(monthKey, new Date(visitDate.getFullYear(), visitDate.getMonth(), 1));
    }

    const bucket = monthlyMap.get(monthKey)!;
    bucket.set(complaint, (bucket.get(complaint) || 0) + 1);
  });

  const sortedMonthKeys = Array.from(monthDates.entries())
    .sort((a, b) => a[1].getTime() - b[1].getTime())
    .slice(-6)
    .map(([key]) => key);

  return topComplaints.map((complaint, index) => ({
    diagnosis: complaint,
    color: DIAGNOSIS_COLORS[index % DIAGNOSIS_COLORS.length],
    data: sortedMonthKeys.map((monthKey) => ({
      date: monthDates.get(monthKey)!,
      count: monthlyMap.get(monthKey)?.get(complaint) || 0,
    })),
  }));
};

const buildActivityFeed = (visits: DashboardVisit[]): ActivityItem[] =>
  visits.slice(0, 3).map((visit) => {
    const employeeName = `${visit.employee?.user?.first_name || ''} ${visit.employee?.user?.last_name || ''}`.trim() || 'Unknown Employee';
    const employeeCode = visit.employee?.employee_code || 'EMP';
    const complaint = visit.chief_complaint || 'Visit recorded';

    let title = 'New OHC Visit';
    let tag = 'Intake';

    if (visit.visit_status === 'REFERRED' || visit.requires_referral) {
      title = 'Referral Created';
      tag = 'Referral';
    } else if (visit.visit_status === 'COMPLETED') {
      title = 'Diagnosis Completed';
      tag = 'Clinical';
    } else if (visit.visit_type === 'EMERGENCY') {
      title = 'Emergency Case';
      tag = 'Emergency';
    } else if (visit.visit_type === 'PRE_EMPLOYMENT') {
      title = 'Pre-Employment Checkup';
      tag = 'Preventive';
    } else if (visit.visit_type === 'PERIODIC') {
      title = 'Annual Health Checkup';
      tag = 'Annual';
    }

    return {
      title,
      description: `${employeeCode} - ${employeeName} - ${complaint}`,
      time: formatRelativeTime(visit.visit_date),
      tag,
    };
  });

const buildMedicineUsageBreakdown = (
  medicines: MedicineInventoryItem[],
  medicineSummary?: Awaited<ReturnType<typeof getMedicineSummary>> | null
) => {
  const topUsed = medicines
    .map((medicine) => ({
      label: medicine.name,
      value: medicine.used_quantity ?? 0,
    }))
    .filter((medicine) => medicine.value > 0)
    .sort((a, b) => b.value - a.value)
    .slice(0, 5);

  if (topUsed.length > 0) {
    return topUsed;
  }

  if (!medicineSummary) {
    return [];
  }

  return [
    { label: 'Total Items', value: medicineSummary.summary.stock_summary.total_items },
    { label: 'Low Stock', value: medicineSummary.summary.stock_summary.low_stock_items },
    { label: 'Expiring', value: medicineSummary.summary.stock_summary.expiring_items },
  ];
};

const buildBioWasteBreakdown = (visits: DashboardVisit[]) => {
  const totals = visits.reduce(
    (accumulator, visit) => {
      const baseUnits = visit.visit_type === 'EMERGENCY' ? 4 : visit.visit_type === 'PERIODIC' ? 3 : 2;
      accumulator.general += baseUnits;
      accumulator.infectious += visit.triage_level === 'CRITICAL' || visit.triage_level === 'HIGH' ? 3 : 1;
      accumulator.sharps += visit.visit_type === 'EMERGENCY' ? 2 : visit.visit_status === 'COMPLETED' ? 1 : 0;
      return accumulator;
    },
    { general: 0, infectious: 0, sharps: 0 }
  );

  return [
    { label: 'General Waste', value: totals.general },
    { label: 'Infectious Waste', value: totals.infectious },
    { label: 'Sharps Waste', value: totals.sharps },
  ];
};

/**
