      key: 'emergencyCount',
      title: 'Emergency Cases',
      description: 'Monthly trend for emergency cases.',
      color: '#d95f5f',
      detailRoute: '/dashboard/metric-details/emergency-count',
    },
    {
      key: 'incidentCount',
      title: 'Incident Cases',
