import React, { useEffect, useMemo, useState } from 'react';
import { useLocation, useNavigate, useParams } from 'react-router-dom';
import api from '../../services/api';
import { Header } from '../layout';
import { Alert, Button, Card, Loading } from '../ui';
import { DepartmentComparisonChart } from '../charts';
import styles from './DepartmentDetailsPage.module.css';

type DepartmentMetricSlug = 'ohc' | 'preamtive' | 'annual';

type DashboardVisit = {
  id: number;
  employee?: {
    employee_code?: string;
    department?: string;
  };
  visit_type?: string;
  visit_status?: string;
  requires_referral?: boolean;
  visit_date?: string;
};

type TrendGranularity = 'daily' | 'monthly' | 'yearly';

type DepartmentPoint = {
  department: string;
  visits: number;
  employees: number;
  referrals: number;
  preamtiveCheckUps: number;
  annualCheckup: number;
};

const isPreEmploymentVisit = (visit: DashboardVisit) => visit.visit_type === 'PRE_EMPLOYMENT';

const isAnnualHealthCheckupVisit = (visit: DashboardVisit) => visit.visit_type === 'PERIODIC';

const isCoreOHCVisit = (visit: DashboardVisit) =>
  !isPreEmploymentVisit(visit) && !isAnnualHealthCheckupVisit(visit);

const METRIC_CONFIG: Record<
  DepartmentMetricSlug,
  {
    title: string;
    subtitle: string;
    dataKey: 'visits' | 'preamtiveCheckUps' | 'annualCheckup';
    titleLabel: string;
    color: string;
  }
> = {
  ohc: {
    title: 'Department-wise OHC Details',
    subtitle: 'Full OHC visit counts for each department',
    dataKey: 'visits',
    titleLabel: 'OHC Visits',
    color: '#0a5f78',
  },
  preamtive: {
    title: 'Department-wise Pre-Employment Checkup Details',
    subtitle: 'Full pre-employment checkup cases for each department',
    dataKey: 'preamtiveCheckUps',
    titleLabel: 'Pre-Employment Checkups',
    color: '#f0b24b',
  },
  annual: {
    title: 'Department-wise Annual Health Checkup Details',
    subtitle: 'Full annual health checkup cases for each department',
    dataKey: 'annualCheckup',
    titleLabel: 'Annual Health Checkups',
    color: '#5aa488',
  },
};

const fetchAllVisits = async (): Promise<DashboardVisit[]> => {
  const visits: DashboardVisit[] = [];
  let page = 1;
  let hasNext = true;

  while (hasNext && page <= 25) {
    const response = await api.get('/ohc/visits/', {
      params: { page, page_size: 200, ordering: '-visit_date' },
    });
    const payload = response.data;
    const batch = Array.isArray(payload) ? payload : payload?.results || [];
    visits.push(...batch);
    hasNext = !Array.isArray(payload) && Boolean(payload?.next);
    page += 1;
  }

  return visits;
};

const isWithinGranularity = (visitDateValue: string | undefined, granularity: TrendGranularity) => {
  if (!visitDateValue) {
    return false;
  }

  const visitDate = new Date(visitDateValue);
  if (Number.isNaN(visitDate.getTime())) {
    return false;
  }

  const now = new Date();

  if (granularity === 'daily') {
    return (
      visitDate.getFullYear() === now.getFullYear() &&
      visitDate.getMonth() === now.getMonth() &&
      visitDate.getDate() === now.getDate()
    );
  }

  if (granularity === 'monthly') {
    return (
      visitDate.getFullYear() === now.getFullYear() &&
      visitDate.getMonth() === now.getMonth()
    );
  }

  return visitDate.getFullYear() === now.getFullYear();
};

const buildDepartmentComparison = (visits: DashboardVisit[]) => {
  const departmentMap = new Map<string, DepartmentPoint & { employeeCodes: Set<string> }>();

  visits.forEach((visit) => {
    const department = visit.employee?.department || 'Unknown';
    const employeeCode = visit.employee?.employee_code || '';

    if (!departmentMap.has(department)) {
      departmentMap.set(department, {
        department,
        visits: 0,
        employees: 0,
        referrals: 0,
        preamtiveCheckUps: 0,
        annualCheckup: 0,
        employeeCodes: new Set<string>(),
      });
    }

    const bucket = departmentMap.get(department)!;
    if (isCoreOHCVisit(visit)) {
      bucket.visits += 1;
    }

    if (employeeCode) {
      bucket.employeeCodes.add(employeeCode);
      bucket.employees = bucket.employeeCodes.size;
    }

    if (visit.requires_referral || visit.visit_status === 'REFERRED') {
      bucket.referrals += 1;
    }

    if (isPreEmploymentVisit(visit)) {
      bucket.preamtiveCheckUps += 1;
    }

    if (isAnnualHealthCheckupVisit(visit)) {
      bucket.annualCheckup += 1;
    }
  });

  return Array.from(departmentMap.values())
    .map(({ employeeCodes: _employeeCodes, ...item }) => item)
    .sort((a, b) => b.visits - a.visits);
};

export const DepartmentDetailsPage: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const { departmentMetricSlug } = useParams<{ departmentMetricSlug: DepartmentMetricSlug }>();
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [allVisits, setAllVisits] = useState<DashboardVisit[]>([]);
  const [granularity, setGranularity] = useState<TrendGranularity>('monthly');

  const metricConfig = departmentMetricSlug ? METRIC_CONFIG[departmentMetricSlug] : null;

  useEffect(() => {
    const params = new URLSearchParams(location.search);
    const requestedGranularity = params.get('granularity');

    if (
      requestedGranularity === 'daily' ||
      requestedGranularity === 'monthly' ||
      requestedGranularity === 'yearly'
    ) {
      setGranularity(requestedGranularity);
    }
  }, [location.search]);

  useEffect(() => {
    const loadData = async () => {
      if (!metricConfig) {
        setError('Department metric not found');
        setLoading(false);
        return;
      }

      try {
        setLoading(true);
        setError('');
        const visits = await fetchAllVisits();
        setAllVisits(visits);
      } catch (err) {
        setError(err instanceof Error ? err.message : 'Failed to load department details');
      } finally {
        setLoading(false);
      }
    };

    loadData();
  }, [metricConfig]);

  const filteredVisits = useMemo(
    () => allVisits.filter((visit) => isWithinGranularity(visit.visit_date, granularity)),
    [allVisits, granularity]
  );

  const departmentData = useMemo(
    () => buildDepartmentComparison(filteredVisits),
    [filteredVisits]
  );

  const total = useMemo(
    () => departmentData.reduce((sum, row) => sum + (row[metricConfig?.dataKey ?? 'visits'] ?? 0), 0),
    [departmentData, metricConfig]
  );

  const granularityLabel =
    granularity === 'daily' ? 'Today' : granularity === 'monthly' ? 'Monthly' : 'Yearly';

  if (loading) {
    return <Loading fullScreen text="Loading department details..." />;
  }

  if (!metricConfig) {
    return <Loading fullScreen text="Loading department details..." />;
  }

  return (
    <div className={styles.page}>
      <Header
        title={metricConfig.title}
        subtitle={metricConfig.subtitle}
        actions={(
          <Button type="button" variant="outline-secondary" onClick={() => navigate('/dashboard')}>
            Back to Dashboard
          </Button>
        )}
      />

      {error && <Alert type="danger" onDismiss={() => setError('')}>{error}</Alert>}

      <main className={styles.main}>
        <div className={styles.controlsRow}>
          <div className={styles.metricFilterWrap}>
            <select
              className={styles.metricFilterSelect}
              value={granularity}
              onChange={(event) => setGranularity(event.target.value as TrendGranularity)}
            >
              <option value="daily">Today</option>
              <option value="monthly">Monthly</option>
              <option value="yearly">Yearly</option>
            </select>
          </div>
        </div>

        <div className={styles.summaryGrid}>
          <Card className={styles.summaryCard}>
            <p className={styles.summaryLabel}>{granularityLabel} {metricConfig.titleLabel}</p>
            <p className={styles.summaryValue}>{total}</p>
          </Card>
          <Card className={styles.summaryCard}>
            <p className={styles.summaryLabel}>{granularityLabel} Departments</p>
            <p className={styles.summaryValue}>{departmentData.length}</p>
          </Card>
        </div>

        <Card className={styles.chartCard}>
          <DepartmentComparisonChart
            data={departmentData}
            dataKey={metricConfig.dataKey}
            titleLabel={metricConfig.titleLabel}
            color={metricConfig.color}
            sortBy={metricConfig.dataKey}
            height={420}
          />
        </Card>

        <Card className={styles.tableCard}>
          <div className={styles.tableWrap}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Department</th>
                  <th>{metricConfig.titleLabel}</th>
                  <th>Employees</th>
                  <th>Referrals</th>
                </tr>
              </thead>
              <tbody>
                {departmentData.map((row) => (
                  <tr key={row.department}>
                    <td>{row.department}</td>
                    <td>{row[metricConfig.dataKey]}</td>
                    <td>{row.employees}</td>
                    <td>{row.referrals}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </Card>
      </main>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Header } from '../layout';
import { Card, FormInput, Loading, Button } from '../ui';
import { getDepartmentHealthStats, exportDepartmentHealthStats } from '../../services/reports';
import { REPORT_PERIOD_OPTIONS } from '../../utils/constants';
import { HealthIndexGauge, VisitsReferralsStackedBar } from '../charts';
import { transformDepartmentStatsData } from '../../utils/charts/transformers';
import styles from './DepartmentStats.module.css';

/**
 * Department Stats page component
 * Display health statistics by department
 */
export const DepartmentStats: React.FC = () => {
  const [period, setPeriod] = useState(90);
  const [loading, setLoading] = useState(true);
  const [chartData, setChartData] = useState<any>({
    healthIndex: [],
    visitsReferrals: [],
  });
  const [chartError, setChartError] = useState<string | null>(null);

  useEffect(() => {
    const loadStats = async () => {
      setLoading(true);
      setChartError(null);
      try {
        const result = await getDepartmentHealthStats(period);
        const transformed = transformDepartmentStatsData(result);
        setChartData(transformed);
      } catch (error) {
        console.error('Failed to load stats:', error);
        setChartError('Failed to load department stats');
      } finally {
        setLoading(false);
      }
    };
    loadStats();
  }, [period]);

  const handleExport = async () => {
    try {
      const blob = await exportDepartmentHealthStats(period);
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `department_stats_${period}days.csv`;
      link.click();
    } catch {
      alert('Export failed');
    }
  };

  if (loading) {
    return <Loading fullScreen />;
  }

  return (
    <div className={styles.departmentStats}>
      <Header
        title="Department Health Statistics"
        subtitle="Health metrics by department"
        actions={
          <>
            <FormInput
              type="select"
              value={period.toString()}
              onChange={(v) => setPeriod(parseInt(v, 10))}
              options={REPORT_PERIOD_OPTIONS}
              className={styles.periodSelect}
            />
            <Button variant="outline-secondary" onClick={handleExport}>
              Export CSV
            </Button>
          </>
        }
      />
      <main className={styles.statsMain}>
        {!loading && chartError && (
          <div className={styles.errorBanner}>
            <p>{chartError}</p>
            <Button variant="brand" size="sm" onClick={() => window.location.reload()}>
              Retry
            </Button>
          </div>
        )}

        {loading ? (
          <Loading fullScreen />
        ) : (
          <>
            <section className={styles.healthIndexSection}>
              <h2 className={styles.sectionTitle}>Department Health Index</h2>
              <div className={styles.gaugesGrid}>
                {chartData.healthIndex.map((dept: any) => (
                  <div key={dept.department} className={styles.gaugeCard}>
                    <HealthIndexGauge data={dept} size={180} showLabel={true} animate={true} />
                    <p className={styles.gaugeLabel}>{dept.department}</p>
                  </div>
                ))}
              </div>
            </section>

            <section className={styles.stackedBarSection}>
              <Card>
                <div className={styles.cardHeader}>
                  <h3>Visits vs Referrals</h3>
                  <Button variant="outline-secondary" size="sm" onClick={handleExport}>
                    Export CSV
                  </Button>
                </div>
                <VisitsReferralsStackedBar data={chartData.visitsReferrals} height={400} />
              </Card>
            </section>
          </>
        )}
      </main>
    </div>
  );
};

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Header } from '../layout';
import { FormInput, Button, Card, Alert } from '../ui';
import { createDiagnosis } from '../../services/ohc';
import { FITNESS_DECISION_OPTIONS, DOSAGE_FREQUENCY_OPTIONS, PRESCRIPTION_ROUTE_OPTIONS } from '../../utils/constants';
import { useSnackbar } from '../../contexts/SnackbarContext';
import { useAuth } from '../../contexts/AuthContext';
import { Severity, FitnessDecision } from '../../types';
import { api } from '../../services/api';
import styles from './DiagnosisEntry.module.css';

interface PrescriptionFormData {
  medicine_name: string;
  dosage: string;
  frequency: string;
  duration_days: number;
  route: string;
  instructions: string;
  start_date: string;
}

/**
 * Diagnosis Entry page component
 * Form to enter diagnosis details with fitness assessment and prescriptions
 */
export const DiagnosisEntry: React.FC = () => {
  const navigate = useNavigate();
  const { show } = useSnackbar();
  const { user } = useAuth();

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [medicineOptions, setMedicineOptions] = useState<Array<{ value: string; label: string }>>([
    { value: '', label: 'Select medicine' },
  ]);

  const [visitId, setVisitId] = useState('');

  const [diagnosis, setDiagnosis] = useState({
    diagnosis_code: '',
    diagnosis_name: '',
    diagnosis_notes: '',
    severity: Severity.MILD,
    is_primary: true,
    is_referral_required: false,
    fitness_decision: FitnessDecision.FIT,
    work_restrictions: '',
    advised_rest_days: 0,
    follow_up_date: '',
  });

  const [prescriptions, setPrescriptions] = useState<PrescriptionFormData[]>([
    {
      medicine_name: '',
      dosage: '',
      frequency: 'Once daily',
      duration_days: 7,
      route: 'Oral',
      instructions: '',
      start_date: new Date().toISOString().split('T')[0],
    },
  ]);

  React.useEffect(() => {
    const fetchMedicines = async () => {
      try {
        const response = await api.get('/ohc/medicines/');
        const data = Array.isArray(response.data) ? response.data : response.data?.results || [];
        const medicineNames = Array.from(
          new Set<string>(
            data
              .filter((medicine: any) => medicine.stock_quantity > 0)
              .map((medicine: any) => String(medicine.name || '').trim())
              .filter((name: string) => Boolean(name)),
          ),
        ).sort((left, right) => left.localeCompare(right));

        setMedicineOptions([
          { value: '', label: 'Select medicine' },
          ...medicineNames.map((name) => ({ value: name, label: name })),
        ]);
      } catch (err) {
        console.error('Failed to fetch medicines:', err);
      }
    };

    fetchMedicines();
  }, []);

  const handleInputChange = (name: string, value: string | number | boolean) => {
    setDiagnosis((prev) => ({ ...prev, [name]: value }));
  };

  const handlePrescriptionChange = (index: number, name: string, value: string | number) => {
    setPrescriptions((prev) =>
      prev.map((prescription, i) =>
        i === index ? { ...prescription, [name]: value } : prescription
      )
    );
  };

  const addPrescription = () => {
    setPrescriptions([
      ...prescriptions,
      {
        medicine_name: '',
        dosage: '',
        frequency: 'Once daily',
        duration_days: 7,
        route: 'Oral',
        instructions: '',
        start_date: new Date().toISOString().split('T')[0],
      },
    ]);
  };

  const removePrescription = (index: number) => {
    if (prescriptions.length > 1) {
      setPrescriptions(prescriptions.filter((_, i) => i !== index));
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    // Validate form
    if (!visitId || !diagnosis.diagnosis_name) {
      setError('Please provide visit ID and diagnosis name');
      show('Please provide visit ID and diagnosis name', 'error');
      return;
    }

    setLoading(true);

    try {
      const validPrescriptions = prescriptions.filter(
        (p) => p.medicine_name && p.dosage
      );

      await createDiagnosis({
        visit: parseInt(visitId, 10),
        diagnosed_by: 0, // Will be filled by backend
        ...diagnosis,
        fitness_decision: user?.role === 'DOCTOR' ? diagnosis.fitness_decision : FitnessDecision.FIT,
        prescriptions: validPrescriptions,
      });

      show('Diagnosis and prescriptions created successfully!', 'success');
      navigate('/dashboard');
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Failed to create diagnosis';
      setError(errorMessage);
      show(errorMessage, 'error');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className={styles.diagnosisForm}>
      <Header
        title="Diagnosis Entry"
        subtitle="Enter diagnosis details with fitness assessment"
      />
      <main className={styles.diagnosisFormMain}>
        {error && <Alert type="danger" onDismiss={() => setError('')}>{error}</Alert>}

        <Card>
          <form onSubmit={handleSubmit}>
            <div className={styles.formSection}>
              <h3>Visit Information</h3>
              <FormInput
                label="Visit UUID *"
                name="visit_id"
                type="text"
                value={visitId}
                onChange={setVisitId}
                placeholder="Enter visit UUID from OHC visit"
                required
                helperText="Find the visit UUID from the OHC visit list"
              />
            </div>

            <div className={styles.formSection}>
              <h3>Diagnosis Details</h3>
              <div className={styles.formGrid}>
                <FormInput
                  label="Diagnosis Code"
                  name="diagnosis_code"
                  type="text"
                  value={diagnosis.diagnosis_code}
                  onChange={(value) => handleInputChange('diagnosis_code', value)}
                  placeholder="e.g., J00.01"
                  helperText="Optional: ICD-10 or local diagnosis code"
                />
                <FormInput
                  label="Diagnosis Name *"
                  name="diagnosis_name"
                  type="text"
                  value={diagnosis.diagnosis_name}
                  onChange={(value) => handleInputChange('diagnosis_name', value)}
                  placeholder="e.g., Acute nasopharyngitis"
                  required
                />
              </div>
              <FormInput
                label="Diagnosis Notes"
                name="diagnosis_notes"
                type="textarea"
                value={diagnosis.diagnosis_notes}
                onChange={(value) => handleInputChange('diagnosis_notes', value)}
                placeholder="Additional clinical notes and observations"
                rows={4}
                className={styles.fullWidth}
              />
            </div>

            <div className={styles.formSection}>
              <h3>Diagnosis Status</h3>
              <div className={styles.formGrid}>
                <FormInput
                  label="Primary Diagnosis"
                  name="is_primary"
                  type="select"
                  value={diagnosis.is_primary.toString()}
                  onChange={(value) => handleInputChange('is_primary', value === 'true')}
                  options={[
                    { value: 'true', label: 'Yes' },
                    { value: 'false', label: 'No' },
                  ]}
                />
                <FormInput
                  label="Requires Referral"
                  name="is_referral_required"
                  type="select"
                  value={diagnosis.is_referral_required.toString()}
                  onChange={(value) => handleInputChange('is_referral_required', value === 'true')}
                  options={[
                    { value: 'true', label: 'Yes' },
                    { value: 'false', label: 'No' },
                  ]}
                />
              </div>
            </div>

            <div className={styles.formSection}>
              <h3>Fitness Assessment</h3>
              <div className={styles.formGrid}>
                {user?.role === 'DOCTOR' && (
                  <FormInput
                    label="Fitness Decision *"
                    name="fitness_decision"
                    type="select"
                    value={diagnosis.fitness_decision}
                    onChange={(value) => handleInputChange('fitness_decision', value)}
                    options={FITNESS_DECISION_OPTIONS}
                    required
                  />
                )}
                <FormInput
                  label="Advised Rest Days"
                  name="advised_rest_days"
                  type="number"
                  value={diagnosis.advised_rest_days}
                  onChange={(value) => handleInputChange('advised_rest_days', parseInt(value) || 0)}
                  placeholder="0"
                  min="0"
                />
                <FormInput
                  label="Follow-up Date"
                  name="follow_up_date"
                  type="date"
                  value={diagnosis.follow_up_date}
                  onChange={(value) => handleInputChange('follow_up_date', value)}
                />
              </div>
              {user?.role === 'DOCTOR' && (
                <FormInput
                  label="Work Restrictions"
                  name="work_restrictions"
                  type="textarea"
                  value={diagnosis.work_restrictions}
                  onChange={(value) => handleInputChange('work_restrictions', value)}
                  placeholder="Specify any work restrictions or modifications"
                  rows={3}
                  className={styles.fullWidth}
                />
              )}
            </div>

            <div className={styles.formSection}>
              <h3>Prescriptions</h3>
              {prescriptions.map((prescription, index) => (
                <div key={index} className={styles.prescriptionCard}>
                  <div className={styles.prescriptionHeader}>
                    <h4>Prescription {index + 1}</h4>
                    {prescriptions.length > 1 && (
                      <Button
                        type="button"
                        variant="outline-danger"
                        size="sm"
                        onClick={() => removePrescription(index)}
                      >
                        Remove
                      </Button>
                    )}
                  </div>
                  <div className={styles.formGrid}>
                    <FormInput
                      label="Medicine Name"
                      name={`medicine_name_${index}`}
                      type="select"
                      value={prescription.medicine_name}
                      onChange={(value) => handlePrescriptionChange(index, 'medicine_name', value)}
                      options={medicineOptions}
                    />
                    <FormInput
                      label="Dosage"
                      name={`dosage_${index}`}
                      type="text"
                      value={prescription.dosage}
                      onChange={(value) => handlePrescriptionChange(index, 'dosage', value)}
                      placeholder="e.g., 1 tablet"
                    />
                    <FormInput
                      label="Frequency"
                      name={`frequency_${index}`}
                      type="select"
                      value={prescription.frequency}
                      onChange={(value) => handlePrescriptionChange(index, 'frequency', value)}
                      options={DOSAGE_FREQUENCY_OPTIONS}
                    />
                    <FormInput
                      label="Duration (days)"
                      name={`duration_days_${index}`}
                      type="number"
                      value={prescription.duration_days}
                      onChange={(value) =>
                        handlePrescriptionChange(index, 'duration_days', parseInt(value) || 7)
                      }
                      min="1"
                    />
                    <FormInput
                      label="Route"
                      name={`route_${index}`}
                      type="select"
                      value={prescription.route}
                      onChange={(value) => handlePrescriptionChange(index, 'route', value)}
                      options={PRESCRIPTION_ROUTE_OPTIONS}
                    />
                    <FormInput
                      label="Start Date"
                      name={`start_date_${index}`}
                      type="date"
                      value={prescription.start_date}
                      onChange={(value) => handlePrescriptionChange(index, 'start_date', value)}
                    />
                  </div>
                  <FormInput
                    label="Instructions"
                    name={`instructions_${index}`}
                    type="textarea"
                    value={prescription.instructions}
                    onChange={(value) => handlePrescriptionChange(index, 'instructions', value)}
                    placeholder="e.g., Take after meals"
                    rows={2}
                    className={styles.fullWidth}
                  />
                </div>
              ))}
              <Button
                type="button"
                variant="outline-brand"
                onClick={addPrescription}
                className={styles.addPrescriptionBtn}
              >
                + Add Prescription
              </Button>
            </div>

            <div className={styles.formActions}>
              <Button
                type="button"
                variant="outline-secondary"
                onClick={() => navigate('/dashboard')}
              >
                Cancel
              </Button>
              <Button type="submit" variant="brand" loading={loading}>
                Create Diagnosis
              </Button>
            </div>
          </form>
        </Card>
      </main>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Header } from '../layout';
import { Card, FormInput, Loading, Button } from '../ui';
import { getDiseaseTrends, exportAnalyticsSummary } from '../../services/reports';
import { REPORT_PERIOD_OPTIONS } from '../../utils/constants';
import { DiagnosisAreaChart, SeverityTrendChart } from '../charts';
import { transformDiseaseTrendsData } from '../../utils/charts/transformers';
import styles from './DiseaseTrends.module.css';

/**
 * Disease Trends page component
 * Display health trends and analytics
 */
export const DiseaseTrends: React.FC = () => {
  const [period, setPeriod] = useState(90);
  const [loading, setLoading] = useState(true);
  const [chartData, setChartData] = useState<any>({
    diagnosisArea: [],
    severityTrends: [],
  });
  const [chartError, setChartError] = useState<string | null>(null);

  useEffect(() => {
    const loadTrends = async () => {
      setLoading(true);
      setChartError(null);
      try {
        const result = await getDiseaseTrends(period);
        const transformed = transformDiseaseTrendsData(result);
        setChartData(transformed);
      } catch (error) {
        console.error('Failed to load trends:', error);
        setChartError('Failed to load disease trends');
      } finally {
        setLoading(false);
      }
    };
    loadTrends();
  }, [period]);

  const handleExport = async () => {
    try {
      const blob = await exportAnalyticsSummary(period, 'trends');
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `disease_trends_${period}days.pdf`;
      link.click();
    } catch {
      alert('Export failed');
    }
  };

  if (loading) {
    return <Loading fullScreen />;
  }

  return (
    <div className={styles.diseaseTrends}>
      <Header
        title="Disease Trends"
        subtitle="Analyze health trends across organization"
        actions={
          <FormInput
            type="select"
            value={period.toString()}
            onChange={(v) => setPeriod(parseInt(v, 10))}
            options={REPORT_PERIOD_OPTIONS}
            className={styles.periodSelect}
          />
        }
      />
      <main className={styles.trendsMain}>
        {!loading && chartError && (
          <div className={styles.errorBanner}>
            <p>{chartError}</p>
            <Button variant="brand" size="sm" onClick={() => window.location.reload()}>
              Retry
            </Button>
          </div>
        )}

        {loading ? (
          <Loading fullScreen />
        ) : (
          <>
            <section className={styles.chartSection}>
              <Card>
                <div className={styles.cardHeader}>
                  <h3>Diagnosis Volume Over Time</h3>
                  <Button variant="outline-secondary" size="sm" onClick={handleExport}>
                    Export PDF
                  </Button>
                </div>
                <DiagnosisAreaChart data={chartData.diagnosisArea} height={400} />
              </Card>
            </section>

            <section className={styles.chartSection}>
              <Card>
                <h3>Severity Distribution Trends</h3>
                <SeverityTrendChart data={chartData.severityTrends} height={350} />
              </Card>
            </section>
          </>
        )}
      </main>
    </div>
  );
};

