            <div className={styles.filterGroup}>
              <label htmlFor="department">Department</label>
              <input
                id="department"
                type="text"
                value={filters.department || ''}
                onChange={(e) => handleFilterChange('department', e.target.value)}
                placeholder="All departments"
              />
            </div>
            <Button type="button" variant="outline-secondary" onClick={fetchAnalytics}>
              Refresh
            </Button>
            <Button type="button" variant="outline-secondary" onClick={handleExport}>
              Export
            </Button>
          </div>
        </Card>

        {analytics && (
          <>
            {/* EHS Statistics Cards - New Section */}
            <div className={styles.ehsStatisticsGrid}>
              <OPDStatisticsCard statistics={ehsStatistics?.opd || null} loading={loading} />
              <PreEmploymentStatisticsCard statistics={ehsStatistics?.preEmployment || null} loading={loading} />
              <AHCStatisticsCard statistics={ehsStatistics?.ahc || null} loading={loading} />
              <IncidentStatisticsCard statistics={ehsStatistics?.incident || null} loading={loading} />
              <EmergencyStatisticsCard statistics={ehsStatistics?.emergency || null} loading={loading} />
              <ReferredStatisticsCard statistics={ehsStatistics?.referred || null} loading={loading} />
            </div>

            {/* Summary Cards */}
            {/* <div className={styles.summaryCards}>
              <Card className={styles.summaryCard}>
                <h3>Total Visits</h3>
                <p className={styles.summaryValue}>{analytics.summary.total_visits}</p>
              </Card>
              <Card className={styles.summaryCard}>
                <h3>Open Cases</h3>
                <p className={styles.summaryValue}>{analytics.summary.open_cases}</p>
              </Card>
              <Card className={styles.summaryCard}>
                <h3>Completed Cases</h3>
                <p className={styles.summaryValue}>{analytics.summary.completed_cases}</p>
              </Card>
              <Card className={styles.summaryCard}>
                <h3>Pending Follow-ups</h3>
                <p className={styles.summaryValue}>{analytics.summary.follow_up_pending}</p>
              </Card>
            </div> */}

            {/* Department-wise Visits */}
            <Card className={styles.chartCard}>
              <h3>Department-wise Visits</h3>
              <div className={styles.chartPlaceholder}>
                {analytics.department_wise.map((dept) => (
                  <div key={dept.department} className={styles.barRow}>
                    <span className={styles.barLabel}>{dept.department}</span>
                    <div className={styles.barTrack}>
                      <div
                        className={styles.barFill}
                        style={{ width: `${dept.percentage}%` }}
                      />
                    </div>
                    <span className={styles.barValue}>{dept.visit_count}</span>
                  </div>
                ))}
              </div>
            </Card>

            {/* Severity Distribution */}
            {/* <Card className={styles.chartCard}>
              <h3>Severity Distribution</h3>
              <div className={styles.severityGrid}>
                <div className={styles.severityItem}>
                  <span className={styles.severityLabel}>Low</span>
                  <span className={styles.severityValue}>{analytics.severity_wise.LOW}</span>
                </div>
                <div className={styles.severityItem}>
                  <span className={styles.severityLabel}>Medium</span>
                  <span className={styles.severityValue}>{analytics.severity_wise.MEDIUM}</span>
                </div>
                <div className={styles.severityItem}>
                  <span className={styles.severityLabel}>High</span>
                  <span className={styles.severityValue}>{analytics.severity_wise.HIGH}</span>
                </div>
                <div className={styles.severityItem}>
                  <span className={styles.severityLabel}>Critical</span>
                  <span className={styles.severityValue}>{analytics.severity_wise.CRITICAL}</span>
                </div>
              </div>
            </Card> */}

            {/* Critical Cases */}
            {analytics.critical_cases.length > 0 && (
              <Card className={styles.listCard}>
                <h3>Critical Cases</h3>
                <div className={styles.listContainer}>
                  {analytics.critical_cases.map((item) => (
                    <div key={item.id} className={styles.listItem}>
                      <div>
                        <span className={styles.itemName}>{item.patient_name}</span>
                        <span className={styles.itemCode}>{item.employee_code}</span>
                      </div>
                      <div className={styles.itemMeta}>
                        <span>{new Date(item.visit_date).toLocaleDateString()}</span>
                        <span className={styles.itemComplaint}>{item.chief_complaint}</span>
                      </div>
                    </div>
                  ))}
                </div>
              </Card>
            )}

            {/* Pending Follow-ups */}
            {analytics.pending_follow_ups.length > 0 && (
              <Card className={styles.listCard}>
                <h3>Pending Follow-ups</h3>
                <div className={styles.listContainer}>
                  {analytics.pending_follow_ups.map((item) => (
                    <div
                      key={item.id}
                      className={`${styles.listItem} ${styles.clickable}`}
                      onClick={() => handleFollowUpClick(item.id)}
                    >
                      <div>
                        <span className={styles.itemName}>{item.patient_name}</span>
                        <span className={styles.itemCode}>{item.employee_code}</span>
                      </div>
                      <div className={styles.itemMeta}>
                        <span>{new Date(item.follow_up_date).toLocaleDateString()}</span>
                        {item.days_overdue > 0 && (
                          <span className={styles.overdueBadge}>{item.days_overdue}d overdue</span>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              </Card>
            )}
          </>
        )}
      </main>

      {/* Follow-up Detail Modal */}
      <Modal
        isOpen={isModalOpen}
        onClose={handleModalClose}
        title="Follow-up Details"
        size="medium"
      >
        {followUpLoading ? (
          <Loading text="Loading details..." />
        ) : selectedFollowUp ? (
          <div className={styles.followUpDetail}>
            <div className={styles.detailSection}>
              <h4>Patient Information</h4>
              <div className={styles.detailRow}>
                <span className={styles.detailLabel}>Name:</span>
                <span className={styles.detailValue}>{selectedFollowUp.patient_name}</span>
              </div>
              <div className={styles.detailRow}>
                <span className={styles.detailLabel}>Employee Code:</span>
                <span className={styles.detailValue}>{selectedFollowUp.employee_code}</span>
              </div>
              <div className={styles.detailRow}>
                <span className={styles.detailLabel}>Department:</span>
                <span className={styles.detailValue}>{selectedFollowUp.department}</span>
              </div>
              <div className={styles.detailRow}>
                <span className={styles.detailLabel}>Email:</span>
                <span className={styles.detailValue}>{selectedFollowUp.employee_contact}</span>
              </div>
              <div className={styles.detailRow}>
                <span className={styles.detailLabel}>Phone:</span>
                <span className={styles.detailValue}>{selectedFollowUp.employee_phone}</span>
              </div>
            </div>

            <div className={styles.detailSection}>
              <h4>Visit Information</h4>
              <div className={styles.detailRow}>
                <span className={styles.detailLabel}>Original Visit Date:</span>
                <span className={styles.detailValue}>
                  {selectedFollowUp.original_visit_date
                    ? new Date(selectedFollowUp.original_visit_date).toLocaleDateString()
                    : 'N/A'}
                </span>
              </div>
              <div className={styles.detailRow}>
                <span className={styles.detailLabel}>Follow-up Date:</span>
                <span className={styles.detailValue}>
                  {selectedFollowUp.follow_up_date
                    ? new Date(selectedFollowUp.follow_up_date).toLocaleDateString()
                    : 'Not scheduled'}
                </span>
              </div>
              <div className={styles.detailRow}>
                <span className={styles.detailLabel}>Visit Status:</span>
                <span className={styles.detailValue}>
                  {selectedFollowUp.visit_status?.replace(/_/g, ' ') || 'Unknown'}
                </span>
              </div>
              <div className={styles.detailRow}>
                <span className={styles.detailLabel}>Triage Level:</span>
                <span className={styles.detailValue}>
                  {selectedFollowUp.triage_level || 'N/A'}
                </span>
              </div>
              <div className={styles.detailRow}>
                <span className={styles.detailLabel}>Follow-up Status:</span>
                <span
                  className={`${styles.detailValue} ${
                    selectedFollowUp.days_overdue > 0 ? styles.overdueText : styles.scheduledText
                  }`}
                >
                  {selectedFollowUp.days_overdue > 0
                    ? `${selectedFollowUp.days_overdue} day${selectedFollowUp.days_overdue > 1 ? 's' : ''} overdue`
                    : 'On schedule'}
                </span>
              </div>
            </div>

            <div className={styles.detailSection}>
              <h4>Clinical Information</h4>
              <div className={styles.detailRow}>
                <span className={styles.detailLabel}>Chief Complaint:</span>
                <span className={styles.detailValue}>{selectedFollowUp.chief_complaint || 'N/A'}</span>
              </div>
              <div className={styles.detailRow}>
                <span className={styles.detailLabel}>Diagnosis:</span>
                <span className={styles.detailValue}>{selectedFollowUp.diagnosis || 'No diagnosis recorded'}</span>
              </div>
              <div className={styles.detailRow}>
                <span className={styles.detailLabel}>Consulted By:</span>
                <span className={styles.detailValue}>{selectedFollowUp.consulted_doctor || 'N/A'}</span>
              </div>
            </div>

            <div className={styles.detailSection}>
              <h4>Notes</h4>
              <div className={styles.detailRow}>
                <span className={styles.detailLabel}>Doctor Notes:</span>
                <p className={styles.detailNotes}>{selectedFollowUp.doctor_notes}</p>
              </div>
              <div className={styles.detailRow}>
                <span className={styles.detailLabel}>Follow-up Instructions:</span>
                <p className={styles.detailNotes}>{selectedFollowUp.follow_up_instructions}</p>
              </div>
            </div>
          </div>
        ) : null}
      </Modal>
    </div>
  );
};

