import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { useSnackbar } from '../../contexts/SnackbarContext';
import { Header } from '../layout';
import { Card, Alert, Button, FormInput } from '../ui';
import { Role } from '../../types';
import api from '../../services/api';
import styles from './EmergencyDetailsPage.module.css';

interface EmergencyCase {
  id: number;
  employee_code: string;
  employee_name: string;
  department: string;
  emergency_date: string;
  chief_complaint: string;
  triage_level: string;
  severity: string;
  visit_status: string;
  description: string;
}

interface AnalyticsData {
  total_emergencies: number;
  today_emergencies: number;
  severity: { LOW: number; MEDIUM: number; HIGH: number; CRITICAL: number };
  department_emergencies: Array<{ department: string; count: number }>;
  trending_emergencies: Array<{ month: string; count: number }>;
}

export const EmergencyDetailsPage: React.FC = () => {
  const navigate = useNavigate();
  const { user } = useAuth();
  const { show } = useSnackbar();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [emergencies, setEmergencies] = useState<EmergencyCase[]>([]);
  const [analytics, setAnalytics] = useState<AnalyticsData | null>(null);

  const [filters, setFilters] = useState({
    date_from: '',
    date_to: '',
    department: '',
    severity: '',
  });

  const handleError = useCallback((err: Error) => {
    const message = err.message || 'Failed to fetch data';
    setError(message);
    show(message, 'error');
  }, [show]);

  const fetchData = async () => {
    try {
      setLoading(true);
      setError('');

      const params: Record<string, string> = {};

      const emergencyKeywords = [
        "heart attack", "unconscious", "fainted", "seizure",
        "stroke", "breathing difficulty", "chest pain",
        "severe pain", "emergency", "collapse"
      ];

      if (filters.date_from) params.date_from = filters.date_from;
      if (filters.date_to) params.date_to = filters.date_to;
      if (filters.department) params.employee__department__icontains = filters.department;
      if (filters.severity) params.triage_level = filters.severity;

      const response = await api.get('/ohc/visits/', { params });
      const data = Array.isArray(response.data) ? response.data : response.data?.results || [];

      // Filter for emergency cases (EMERGENCY type OR emergency keywords)
      const emergencyVisits = data.filter((visit: any) => {
        const complaint = visit.chief_complaint?.toLowerCase() || '';
        const isEmergency = emergencyKeywords.some((keyword: string) =>
          complaint.includes(keyword)
        );
        const isEmergencyType = visit.visit_type === 'EMERGENCY';
        return isEmergency || isEmergencyType;
      });

      setEmergencies(emergencyVisits);

      const severityMap = { LOW: 0, MEDIUM: 0, HIGH: 0, CRITICAL: 0 };
      const deptMap: Record<string, number> = {};
      const monthMap: Record<string, number> = {};

      const today = new Date().toISOString().split('T')[0];

      emergencyVisits.forEach((visit: any) => {
        const rawSeverity = visit.triage_level || 'LOW';
        const severity = rawSeverity as keyof typeof severityMap;

        // Only increment if severity is a valid key
        if (severity in severityMap) {
          severityMap[severity] = (severityMap[severity] || 0) + 1;
        }

        const dept = visit.employee?.department || 'Unknown';
        deptMap[dept] = (deptMap[dept] || 0) + 1;

        const month = visit.visit_date?.split('T')[0] || 'Unknown';
        monthMap[month] = (monthMap[month] || 0) + 1;
      });

      const todayEmergencies = emergencyVisits.filter((v: any) => v.visit_date?.split('T')[0] === today).length;

      const departmentEmergencies = Object.entries(deptMap).map(([department, count]) => ({
        department,
        count,
      })).sort((a, b) => b.count - a.count);

      const trendingEmergencies = Object.entries(monthMap).map(([month, count]) => ({
        month,
        count,
      }));

      setAnalytics({
        total_emergencies: emergencyVisits.length,
        today_emergencies: todayEmergencies,
        severity: severityMap,
        department_emergencies: departmentEmergencies,
        trending_emergencies: trendingEmergencies,
      });
    } catch (err) {
      handleError(err as Error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (!user || (user.role !== Role.EHS && user.role !== Role.MANAGEMENT)) {
      setError('Access restricted to EHS and Management users only');
      return;
    }
    fetchData();
  }, [user, filters]);

  const handleFilterChange = (key: keyof typeof filters, value: string) => {
    setFilters((prev) => ({ ...prev, [key]: value }));
  };

  return (
    <div className={styles.emergencyDetailsPage}>
      <Header
        title="Emergency Cases Details"
        subtitle="Detailed view of medical emergencies"
        actions={
          <Button type="button" variant="outline-secondary" onClick={() => navigate('/ehs/dashboard')}>
            ΓåÉ Back to Dashboard
          </Button>
        }
      />

      {error && <Alert type="danger" onDismiss={() => setError('')}>{error}</Alert>}

      <main className={styles.main}>
        <Card className={styles.filterCard}>
          <div className={styles.filterRow}>
            <FormInput
              label="From Date"
              type="date"
              value={filters.date_from}
              onChange={(value) => handleFilterChange('date_from', value)}
            />
            <FormInput
              label="To Date"
              type="date"
              value={filters.date_to}
              onChange={(value) => handleFilterChange('date_to', value)}
            />
            <FormInput
              label="Department"
              type="text"
              value={filters.department}
              onChange={(value) => handleFilterChange('department', value)}
              placeholder="All departments"
            />
            <FormInput
              type="select"
              label="Severity"
              value={filters.severity}
              onChange={(value) => handleFilterChange('severity', value)}
              options={[
                { value: '', label: 'All Severities' },
                { value: 'LOW', label: 'Low' },
                { value: 'MEDIUM', label: 'Medium' },
                { value: 'HIGH', label: 'High' },
                { value: 'CRITICAL', label: 'Critical' },
              ]}
            />
            <Button type="button" variant="brand" onClick={fetchData} loading={loading}>
              Apply Filters
            </Button>
            <Button type="button" variant="outline-secondary" onClick={() => setFilters({ date_from: '', date_to: '', department: '', severity: '' })}>
              Clear
            </Button>
          </div>
        </Card>

        {analytics && (
          <>
            <div className={styles.summaryGrid}>
              <Card className={styles.summaryCard}>
                <div className={styles.summaryValue}>{analytics.total_emergencies}</div>
                <div className={styles.summaryLabel}>Total Emergencies</div>
              </Card>
              <Card className={`${styles.summaryCard} ${styles.todayCard}`}>
                <div className={styles.summaryValue}>{analytics.today_emergencies}</div>
                <div className={styles.summaryLabel}>Today's Emergencies</div>
              </Card>
              <Card className={`${styles.summaryCard} ${styles.criticalCard}`}>
                <div className={styles.summaryValue}>{analytics.severity.CRITICAL}</div>
                <div className={styles.summaryLabel}>Critical</div>
              </Card>
              <Card className={styles.rateCard}>
                <div className={styles.summaryValue}>
                  {analytics.total_emergencies > 0 ? Math.round(((analytics.severity.HIGH + analytics.severity.CRITICAL) / analytics.total_emergencies) * 100) : 0}%
                </div>
                <div className={styles.summaryLabel}>Critical Rate</div>
              </Card>
            </div>

            <Card className={styles.severityCard}>
              <h3>Severity Breakdown</h3>
              <div className={styles.severityGrid}>
                <div className={styles.severityItem}>
                  <span className={`${styles.severityBadge} ${styles.low}`}>
                    LOW
                  </span>
                  <span className={styles.severityValue}>{analytics.severity.LOW}</span>
                </div>
                <div className={styles.severityItem}>
                  <span className={`${styles.severityBadge} ${styles.medium}`}>
                    MEDIUM
                  </span>
                  <span className={styles.severityValue}>{analytics.severity.MEDIUM}</span>
                </div>
                <div className={styles.severityItem}>
                  <span className={`${styles.severityBadge} ${styles.high}`}>
                    HIGH
                  </span>
                  <span className={styles.severityValue}>{analytics.severity.HIGH}</span>
                </div>
                <div className={styles.severityItem}>
                  <span className={`${styles.severityBadge} ${styles.critical}`}>
                    CRITICAL
                  </span>
                  <span className={styles.severityValue}>{analytics.severity.CRITICAL}</span>
                </div>
              </div>
            </Card>

            <Card className={styles.chartCard}>
              <h3>Department Emergencies</h3>
              <div className={styles.barContainer}>
                {analytics.department_emergencies.slice(0, 5).map((dept) => (
                  <div key={dept.department} className={styles.barRow}>
                    <span className={styles.barLabel}>{dept.department}</span>
                    <div className={styles.barTrack}>
                      <div
                        className={styles.barFill}
                        style={{
                          width: `${analytics.total_emergencies > 0 ? (dept.count / analytics.total_emergencies) * 100 : 0}%`,
                          background: dept.count > 5 ? '#dc2626' : dept.count > 2 ? '#f97316' : '#f59e0b',
                        }}
                      />
                    </div>
                    <span className={styles.barValue}>{dept.count}</span>
                  </div>
                ))}
              </div>
            </Card>
          </>
        )}

        <Card className={styles.listCard}>
          <h3>Emergency Cases ({emergencies.length})</h3>
          {emergencies.length === 0 ? (
            <div className={styles.emptyState}>No emergency cases found</div>
          ) : (
            <table className={styles.emergenciesTable}>
              <thead>
                <tr>
                  <th>Employee</th>
                  <th>Code</th>
                  <th>Department</th>
                  <th>Emergency Date</th>
                  <th>Complaint</th>
                  <th>Severity</th>
                  <th>Status</th>
                </tr>
              </thead>
              <tbody>
                {emergencies.map((emergency) => (
                  <tr key={emergency.id}>
                    <td>{emergency.employee_name || '-'}</td>
                    <td>{emergency.employee_code || '-'}</td>
                    <td>{emergency.department || '-'}</td>
                    <td>{new Date(emergency.emergency_date).toLocaleDateString()}</td>
                    <td className={styles.complaintCell}>{emergency.chief_complaint || '-'}</td>
                    <td>
                      <span className={`${styles.severityBadge} ${styles[(emergency.triage_level || 'LOW').toLowerCase()]}`}>
                        {emergency.triage_level || 'LOW'}
                      </span>
                    </td>
                    <td>
                      <span className={`${styles.statusBadge} ${styles[(emergency.visit_status || 'OPEN').toLowerCase().replace('_', '')]}`}>
                        {emergency.visit_status?.replace('_', ' ') || 'Open'}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </Card>
      </main>
    </div>
  );
};

import React, { useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Header } from '../layout';
import { Alert, Card, FormInput, Button, Loading } from '../ui';
import {
  exportEmployeeHealthHistory,
  getEmployeeHealthHistory,
} from '../../services/reports';
import { REPORT_PERIOD_OPTIONS } from '../../utils/constants';
import type {
  EmployeeHealthHistoryList,
} from '../../types';
import styles from './EmployeeHealthHistory.module.css';

/**
 * Employee Health History page component
 * Display and export employee health records
 */
export const EmployeeHealthHistory: React.FC = () => {
  const navigate = useNavigate();
  const [employeeId, setEmployeeId] = useState('');
  const [period, setPeriod] = useState(90);
  const [loading, setLoading] = useState(false);
  const [data, setData] = useState<EmployeeHealthHistoryList | null>(null);
  const [error, setError] = useState('');

  const loadHistory = async (targetEmployeeId?: string) => {
    setLoading(true);
    setError('');
    try {
      const result = await getEmployeeHealthHistory(targetEmployeeId || undefined);
      if ('records' in result) {
        setData(result);
      } else if (targetEmployeeId) {
        navigate(`/reports/employee-history/${targetEmployeeId}`);
      }
    } catch {
      setError('Failed to load employee history');
    } finally {
      setLoading(false);
    }
  };

  const handleLoad = async () => {
    await loadHistory(employeeId || undefined);
  };

  const handleExportAll = async () => {
    try {
      const blob = await exportEmployeeHealthHistory(employeeId || undefined);
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = employeeId
        ? `employee_${employeeId}_health_history.pdf`
        : 'all_employee_health_history.pdf';
      link.click();
    } catch {
      setError('Export failed');
    }
  };

  const handleViewRecord = async (targetEmployeeId: string) => {
    setEmployeeId(targetEmployeeId);
    navigate(`/reports/employee-history/${targetEmployeeId}`);
  };

  const isListMode = data !== null;
  const records = data?.records || [];
  const summary = useMemo(() => {
    const uniqueEmployees = new Set(records.map((record) => record.employee_code)).size;
    const fitCases = records.filter((record) => String(record.fitness_decision || '').includes('FIT')).length;
    const referredCases = records.filter((record) => record.referral_status).length;

    return {
      totalRecords: records.length,
      uniqueEmployees,
      fitCases,
      referredCases,
    };
  }, [records]);

  return (
    <div className={styles.healthHistory}>
      <Header title="Employee Health History" subtitle="View complete health records" />
      <main className={styles.healthMain}>
        {error && <Alert type="danger" onDismiss={() => setError('')}>{error}</Alert>}

        <Card className={styles.heroCard}>
          <div className={styles.heroContent}>
            <div>
              <p className={styles.eyebrow}>History Workspace</p>
              <h2 className={styles.heroTitle}>Track employee health records in one place</h2>
              <p className={styles.heroText}>
                Search by employee ID, review visit history, and export records for reporting.
              </p>
            </div>
            <div className={styles.heroMeta}>
              <span className={styles.heroMetaLabel}>Selected period</span>
              <strong className={styles.heroMetaValue}>{period} days</strong>
            </div>
          </div>
        </Card>

        <Card className={styles.searchCard}>
          <div className={styles.searchHeader}>
            <div>
              <h3>Find Records</h3>
              <p>Load a single employee history or review all available records.</p>
            </div>
          </div>
          <div className={styles.searchGrid}>
            <FormInput
              label="Employee ID"
              value={employeeId}
              onChange={setEmployeeId}
              placeholder="Enter employee ID or leave blank"
            />
            <FormInput
              label="Period"
              type="select"
              value={period.toString()}
              onChange={(v) => setPeriod(parseInt(v, 10))}
              options={REPORT_PERIOD_OPTIONS}
            />
            <Button variant="outline-secondary" onClick={handleExportAll}>
              Export PDF
            </Button>
            <Button onClick={handleLoad}>Load</Button>
          </div>
        </Card>

        {loading && <Loading />}

        {isListMode && data && (
          <>
            <section className={styles.summaryCards}>
              <Card className={styles.metricCard}>
                <span className={styles.metricLabel}>Total Records</span>
                <strong className={styles.metricValue}>{summary.totalRecords}</strong>
              </Card>
              <Card className={styles.metricCard}>
                <span className={styles.metricLabel}>Employees</span>
                <strong className={styles.metricValue}>{summary.uniqueEmployees}</strong>
              </Card>
              <Card className={styles.metricCard}>
                <span className={styles.metricLabel}>Fit Cases</span>
                <strong className={styles.metricValue}>{summary.fitCases}</strong>
              </Card>
              <Card className={styles.metricCard}>
                <span className={styles.metricLabel}>Referred Cases</span>
                <strong className={styles.metricValue}>{summary.referredCases}</strong>
              </Card>
            </section>

            <Card className={styles.visitsCard}>
              <div className={styles.cardHeader}>
                <div>
                  <h3>Employee Records</h3>
                  <p className={styles.cardSubtext}>{data.records.length} records loaded</p>
                </div>
              </div>
              <div className={styles.tableWrap}>
                <table className={styles.recordsTable}>
                  <thead>
                    <tr>
                      <th>Employee</th>
                      <th>Visit Date</th>
                      <th>Complaint</th>
                      <th>Doctor</th>
                      <th>Fitness</th>
                      <th>Action</th>
                    </tr>
                  </thead>
                  <tbody>
                    {data.records.map((record) => (
                      <tr key={record.visit_id}>
                        <td>
                          <div className={styles.employeeCell}>
                            <strong>{record.employee_name}</strong>
                            <span>{record.employee_code}</span>
                          </div>
                        </td>
                        <td>{record.visit_date}</td>
                        <td className={styles.complaintCell}>{record.chief_complaint}</td>
                        <td>{record.doctor_name}</td>
                        <td>
                          <span className={styles.fitnessBadge}>
                            {record.fitness_decision || '-'}
                          </span>
                        </td>
                        <td>
                          <Button
                            variant="outline-secondary"
                            size="sm"
                            onClick={() => handleViewRecord(record.employee_code)}
                          >
                            View
                          </Button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </Card>
          </>
        )}

        {isListMode && data && data.records.length === 0 && (
          <Card className={styles.emptyCard}>
            <h3>No records found</h3>
            <p>Try another employee ID or load all records without a filter.</p>
          </Card>
        )}
      </main>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Header } from '../layout';
import { Alert, Button, Card, Loading } from '../ui';
import { exportEmployeeHealthHistory, getEmployeeHealthHistory } from '../../services/reports';
import type { EmployeeHealthHistory } from '../../types';
import styles from './EmployeeHealthHistory.module.css';

/**
 * Employee Health History detail page
 * Shows the complete history for one employee on a dedicated screen
 */
export const EmployeeHealthHistoryDetail: React.FC = () => {
  const navigate = useNavigate();
  const { employeeId = '' } = useParams();
  const [loading, setLoading] = useState(true);
  const [data, setData] = useState<EmployeeHealthHistory | null>(null);
  const [error, setError] = useState('');

  useEffect(() => {
    const loadHistory = async () => {
      setLoading(true);
      setError('');
      try {
        const result = await getEmployeeHealthHistory(employeeId);
        if ('employee' in result) {
          setData(result);
        } else {
          setError('Failed to load employee history');
        }
      } catch {
        setError('Failed to load employee history');
      } finally {
        setLoading(false);
      }
    };

    loadHistory();
  }, [employeeId]);

  const handleExport = async () => {
    if (!data) return;
    try {
      const blob = await exportEmployeeHealthHistory(data.employee.employee_code);
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `employee_${data.employee.employee_code}_health_receipt.pdf`;
      link.click();
    } catch {
      setError('Export failed');
    }
  };

  return (
    <div className={styles.healthHistory}>
      <Header
        title="Employee Health History"
        subtitle="View complete health records"
        actions={(
          <Button type="button" variant="outline-secondary" onClick={() => navigate('/reports/employee-history')}>
            Back
          </Button>
        )}
      />
      <main className={styles.healthMain}>
        {error && <Alert type="danger" onDismiss={() => setError('')}>{error}</Alert>}
        {loading && <Loading />}

        {!loading && data && (
          <>
            <Card className={styles.summaryCard}>
              <div className={styles.summaryTop}>
                <div>
                  <p className={styles.eyebrow}>Employee Summary</p>
                  <h2 className={styles.summaryName}>
                    {data.employee.user.first_name} {data.employee.user.last_name}
                  </h2>
                </div>
                <span className={styles.fitnessBadge}>{data.employee.fitness_status}</span>
              </div>
              <div className={styles.summaryMetaGrid}>
                <div className={styles.metaBlock}>
                  <span className={styles.metaLabel}>Employee ID</span>
                  <strong>{data.employee.employee_code}</strong>
                </div>
                <div className={styles.metaBlock}>
                  <span className={styles.metaLabel}>Department</span>
                  <strong>{data.employee.department}</strong>
                </div>
                <div className={styles.metaBlock}>
                  <span className={styles.metaLabel}>Designation</span>
                  <strong>{data.employee.designation}</strong>
                </div>
                <div className={styles.metaBlock}>
                  <span className={styles.metaLabel}>Visits</span>
                  <strong>{data.visits.length}</strong>
                </div>
              </div>
            </Card>

            <Card className={styles.visitsCard}>
              <div className={styles.cardHeader}>
                <div>
                  <h3>Visit Timeline</h3>
                  <p className={styles.cardSubtext}>{data.visits.length} visits recorded</p>
                </div>
                <Button variant="outline-secondary" size="sm" onClick={handleExport}>
                  Export PDF Receipt
                </Button>
              </div>
              <div className={styles.visitsList}>
                {data.visits.map((visit) => (
                  <div key={visit.id} className={styles.visitItem}>
                    <div className={styles.visitHeader}>
                      <div>
                        <h4>{visit.chief_complaint || 'Visit Record'}</h4>
                        <p className={styles.visitMetaLine}>
                          {visit.visit_date} ΓÇó {visit.visit_type} ΓÇó {visit.visit_status}
                        </p>
                      </div>
                      <span className={styles.visitStatusBadge}>{visit.visit_status}</span>
                    </div>

                    <div className={styles.visitGrid}>
                      <div className={styles.metaBlock}>
                        <span className={styles.metaLabel}>Doctor</span>
                        <strong>{visit.doctor_name || '-'}</strong>
                      </div>
                      <div className={styles.metaBlock}>
                        <span className={styles.metaLabel}>Triage Level</span>
                        <strong>{visit.triage_level || '-'}</strong>
                      </div>
                      <div className={styles.metaBlock}>
                        <span className={styles.metaLabel}>Referral</span>
                        <strong>{visit.requires_referral ? 'Yes' : 'No'}</strong>
                      </div>
                      {visit.follow_up_date && (
                        <div className={styles.metaBlock}>
                          <span className={styles.metaLabel}>Follow-up</span>
                          <strong>{visit.follow_up_date}</strong>
                        </div>
                      )}
                    </div>

                    {visit.symptoms && (
                      <div className={styles.detailBlock}>
                        <p className={styles.blockTitle}>Symptoms</p>
                        <p className={styles.bodyText}>{visit.symptoms}</p>
                      </div>
                    )}
                    {visit.vitals && Object.keys(visit.vitals).length > 0 && (
                      <div className={styles.detailBlock}>
                        <p className={styles.blockTitle}>Vitals</p>
                        <div className={styles.vitalsChipGrid}>
                          {Object.entries(visit.vitals).map(([key, value]) => (
                            <span key={key} className={styles.vitalChip}>
                              <strong>{key}:</strong> {String(value)}
                            </span>
                          ))}
                        </div>
                      </div>
                    )}
                    {visit.preliminary_notes && (
                      <div className={styles.detailBlock}>
                        <p className={styles.blockTitle}>Preliminary Notes</p>
                        <p className={styles.bodyText}>{visit.preliminary_notes}</p>
                      </div>
                    )}
                    {visit.next_action && (
                      <div className={styles.detailBlock}>
                        <p className={styles.blockTitle}>Next Action</p>
                        <p className={styles.bodyText}>{visit.next_action}</p>
                      </div>
                    )}
                    {visit.diagnoses && visit.diagnoses.length > 0 && (
                      <div className={styles.detailBlock}>
                        <p className={styles.blockTitle}>Diagnoses</p>
                        <div className={styles.detailList}>
                          {visit.diagnoses.map((diagnosis: any) => (
                            <div key={`${visit.id}-${diagnosis.diagnosis_name}-${diagnosis.diagnosed_at}`} className={styles.inlineRecord}>
                              <strong>{diagnosis.diagnosis_name}</strong>
                              <span>{diagnosis.fitness_decision}</span>
                            </div>
                          ))}
                        </div>
                      </div>
                    )}
                    {visit.prescriptions && visit.prescriptions.length > 0 && (
                      <div className={styles.detailBlock}>
                        <p className={styles.blockTitle}>Prescriptions</p>
                        <div className={styles.detailList}>
                          {visit.prescriptions.map((prescription: any) => (
                            <div key={`${visit.id}-${prescription.medicine_name}-${prescription.start_date}`} className={styles.inlineRecord}>
                              <strong>{prescription.medicine_name}</strong>
                              <span>{prescription.dosage}</span>
                              <span>Start {prescription.start_date}</span>
                            </div>
                          ))}
                        </div>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </Card>
          </>
        )}
      </main>
    </div>
  );
};

