import { describe, it, expect, vi, beforeEach } from 'vitest';
import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { ErrorBoundary } from '../ErrorBoundary';

const ThrowError = () => { throw new Error('Test error'); };

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { render, screen, act } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import React from 'react';
import { SnackbarProvider, useSnackbar } from '../SnackbarContext';

// Helper component that exposes snackbar API
const TestConsumer: React.FC = () => {
  const { show, close, isOpen, currentMessage } = useSnackbar();
  return (
    <div>
      <span data-testid="status">{isOpen ? 'open' : 'closed'}</span>
      <span data-testid="message">{currentMessage?.message ?? 'none'}</span>
      <span data-testid="severity">{currentMessage?.severity ?? 'none'}</span>
      <button onClick={() => show('Test message')}>Show Default</button>
      <button onClick={() => show('Success!', 'success')}>Show Success</button>
      <button onClick={() => show('Error!', 'error', 1000)}>Show Error</button>
      <button onClick={close}>Close</button>
    </div>
  );
};

describe('SnackbarContext', () => {
  beforeEach(() => vi.useFakeTimers());
  afterEach(() => vi.useRealTimers());

  const renderSnackbar = () => render(
    <SnackbarProvider><TestConsumer /></SnackbarProvider>
  );

  it('provides show and close functions', () => {
    renderSnackbar();
    expect(screen.getByText('Show Default')).toBeInTheDocument();
    expect(screen.getByText('Close')).toBeInTheDocument();
  });

  it('starts with closed state', () => {
    renderSnackbar();
    expect(screen.getByTestId('status')).toHaveTextContent('closed');
    expect(screen.getByTestId('message')).toHaveTextContent('none');
  });

  it('show() sets isOpen to true and sets message', async () => {
    renderSnackbar();
    await act(async () => {
      screen.getByText('Show Default').click();
    });
    expect(screen.getByTestId('status')).toHaveTextContent('open');
    expect(screen.getByTestId('message')).toHaveTextContent('Test message');
  });

  it('show() defaults severity to info', async () => {
    renderSnackbar();
    await act(async () => {
      screen.getByText('Show Default').click();
    });
    expect(screen.getByTestId('severity')).toHaveTextContent('info');
  });

  it('show() sets correct severity', async () => {
    renderSnackbar();
    await act(async () => {
      screen.getByText('Show Success').click();
    });
    expect(screen.getByTestId('severity')).toHaveTextContent('success');
  });

  it('close() sets isOpen to false', async () => {
    renderSnackbar();
    await act(async () => { screen.getByText('Show Default').click(); });
    expect(screen.getByTestId('status')).toHaveTextContent('open');
    await act(async () => { screen.getByText('Close').click(); });
    expect(screen.getByTestId('status')).toHaveTextContent('closed');
  });

  it('auto-dismisses after duration', async () => {
    renderSnackbar();
    await act(async () => { screen.getByText('Show Error').click(); });
    expect(screen.getByTestId('status')).toHaveTextContent('open');
    await act(async () => { vi.advanceTimersByTime(1000); });
    expect(screen.getByTestId('status')).toHaveTextContent('closed');
  });

  it('replaces current message on subsequent show()', async () => {
    renderSnackbar();
    await act(async () => { screen.getByText('Show Default').click(); });
    expect(screen.getByTestId('message')).toHaveTextContent('Test message');
    await act(async () => { screen.getByText('Show Success').click(); });
    expect(screen.getByTestId('message')).toHaveTextContent('Success!');
  });

  it('useSnackbar throws outside provider', () => {
    const Broken = () => { useSnackbar(); return null; };
    expect(() => render(<Broken />)).toThrow('useSnackbar must be used within a SnackbarProvider');
  });
});

import { renderHook, act, waitFor } from '@testing-library/react';
import { useExport, type ExportFormat } from '../useExport';

jest.mock('html2canvas');
jest.mock('jspdf');

describe('useExport', () => {
  let mockHtml2Canvas: jest.Mock;
  let mockJsPDF: jest.MockedClass<any>;
  let mockCanvas: HTMLCanvasElement;

  beforeEach(() => {
    jest.clearAllMocks();

    mockCanvas = document.createElement('canvas');
    mockCanvas.width = 800;
    mockCanvas.height = 600;

    mockHtml2Canvas = require('html2canvas').default;
    mockHtml2Canvas.mockResolvedValue(mockCanvas);

    mockJsPDF = require('jspdf').jsPDF;
    mockJsPDF.mockImplementation(() => ({
      addImage: jest.fn(),
      save: jest.fn(),
    }));

    document.body.innerHTML = '<div id="test-chart">Test Content</div>';
  });

  it('exports chart as PNG', async () => {
    const { result } = renderHook(() => useExport());

    const linkSpy = jest.spyOn(document, 'createElement').mockReturnValue({
      download: '',
      href: '',
      click: jest.fn(),
    } as unknown as HTMLAnchorElement);

    await act(async () => {
      await result.current.exportChart('test-chart', { format: 'png' });
    });

    await waitFor(() => {
      expect(result.current.isExporting).toBe(false);
    });

    expect(mockHtml2Canvas).toHaveBeenCalled();
    expect(linkSpy).toHaveBeenCalled();

    linkSpy.mockRestore();
  });

  it('exports chart as PDF', async () => {
    const { result } = renderHook(() => useExport());

    await act(async () => {
      await result.current.exportChart('test-chart', { format: 'pdf' });
    });

    await waitFor(() => {
      expect(result.current.isExporting).toBe(false);
    });

    expect(mockJsPDF).toHaveBeenCalled();
  });

  it('sets exporting state correctly', async () => {
    const { result } = renderHook(() => useExport());
    mockHtml2Canvas.mockImplementation(
      () => new Promise((resolve) => setTimeout(() => resolve(mockCanvas), 100))
    );

    const exportPromise = act(async () => {
      result.current.exportChart('test-chart', { format: 'png' });
    });

    expect(result.current.isExporting).toBe(true);

    await exportPromise;

    await waitFor(() => {
      expect(result.current.isExporting).toBe(false);
    });
  });

  it('updates export progress', async () => {
    const { result } = renderHook(() => useExport());

    const progressUpdates: number[] = [];
    const originalExport = result.current.exportChart.bind(result.current);

    result.current.exportChart = async (...args) => {
      const promise = originalExport(...args);
      progressUpdates.push(result.current.exportProgress);
      await promise;
      return promise;
    };

    await act(async () => {
      await result.current.exportChart('test-chart', { format: 'png' });
    });

    await waitFor(() => {
      expect(result.current.exportProgress).toBe(0);
    });
  });

  it('handles export errors', async () => {
    const { result } = renderHook(() => useExport());
    mockHtml2Canvas.mockRejectedValue(new Error('Export failed'));

    await act(async () => {
      await expect(
        result.current.exportChart('test-chart', { format: 'png' })
      ).rejects.toThrow('Export failed');
    });

    await waitFor(() => {
      expect(result.current.isExporting).toBe(false);
    });
  });

  it('generates share URL with params', () => {
    const { result } = renderHook(() => useExport());

    const url = result.current.generateShareUrl('https://example.com', {
      dept: 'IT',
      severity: 'MILD',
    });

    expect(url).toContain('dept=IT');
    expect(url).toContain('severity=MILD');
  });

  it('copies to clipboard', async () => {
    const { result } = renderHook(() => useExport());
    const clipboardSpy = jest
      .spyOn(navigator, 'clipboard', 'get')
      .mockReturnValue({
        writeText: jest.fn().mockResolvedValue(undefined),
      } as unknown as Clipboard);

    const success = await result.current.copyToClipboard('test text');

    expect(success).toBe(true);
    expect(clipboardSpy.writeText).toHaveBeenCalledWith('test text');

    clipboardSpy.mockRestore();
  });

  it('exports multiple charts', async () => {
    document.body.innerHTML =
      '<div id="chart1">Chart 1</div><div id="chart2">Chart 2</div>';

    const { result } = renderHook(() => useExport());

    await act(async () => {
      await result.current.exportMultiple([
        { id: 'chart1', options: { format: 'png' } },
        { id: 'chart2', options: { format: 'png' } },
      ]);
    });

    await waitFor(() => {
      expect(result.current.isExporting).toBe(false);
    });

    expect(mockHtml2Canvas).toHaveBeenCalledTimes(2);
  });

  it('handles non-existent element', async () => {
    const { result } = renderHook(() => useExport());

    await act(async () => {
      await expect(
        result.current.exportChart('non-existent', { format: 'png' })
      ).rejects.toThrow('Element not found');
    });
  });
});

import { renderHook, act } from '@testing-library/react';
import { useFilters, type DashboardFilters } from '../useFilters';

describe('useFilters', () => {
  beforeEach(() => {
    localStorage.clear();
  });

  it('initializes with default empty filters', () => {
    const { result } = renderHook(() => useFilters());

    expect(result.current.filters.dateRange.start).toBeNull();
    expect(result.current.filters.dateRange.end).toBeNull();
    expect(result.current.filters.departments).toEqual([]);
    expect(result.current.filters.severities).toEqual([]);
    expect(result.current.filters.diagnoses).toEqual([]);
    expect(result.current.filters.employeeCodes).toEqual([]);
  });

  it('updates date range', () => {
    const { result } = renderHook(() => useFilters());
    const start = new Date('2026-01-01');
    const end = new Date('2026-01-31');

    act(() => {
      result.current.setDateRange(start, end);
    });

    expect(result.current.filters.dateRange.start).toEqual(start);
    expect(result.current.filters.dateRange.end).toEqual(end);
    expect(result.current.isDirty).toBe(true);
  });

  it('toggles department selection', () => {
    const { result } = renderHook(() => useFilters());

    act(() => {
      result.current.toggleDepartment('IT');
    });

    expect(result.current.filters.departments).toContain('IT');
    expect(result.current.isDirty).toBe(true);

    act(() => {
      result.current.toggleDepartment('IT');
    });

    expect(result.current.filters.departments).not.toContain('IT');
  });

  it('toggles severity selection', () => {
    const { result } = renderHook(() => useFilters());

    act(() => {
      result.current.toggleSeverity('MILD');
    });

    expect(result.current.filters.severities).toContain('MILD');

    act(() => {
      result.current.toggleSeverity('MILD');
    });

    expect(result.current.filters.severities).not.toContain('MILD');
  });

  it('toggles diagnosis selection', () => {
    const { result } = renderHook(() => useFilters());

    act(() => {
      result.current.toggleDiagnosis('Flu');
    });

    expect(result.current.filters.diagnoses).toContain('Flu');
  });

  it('adds and removes employee codes', () => {
    const { result } = renderHook(() => useFilters());

    act(() => {
      result.current.addEmployeeCode('EMP001');
    });

    expect(result.current.filters.employeeCodes).toContain('EMP001');

    act(() => {
      result.current.removeEmployeeCode('EMP001');
    });

    expect(result.current.filters.employeeCodes).not.toContain('EMP001');
  });

  it('does not add duplicate employee codes', () => {
    const { result } = renderHook(() => useFilters());

    act(() => {
      result.current.addEmployeeCode('EMP001');
    });
    act(() => {
      result.current.addEmployeeCode('EMP001');
    });

    expect(result.current.filters.employeeCodes).toEqual(['EMP001']);
  });

  it('resets filters to defaults', () => {
    const { result } = renderHook(() => useFilters());

    act(() => {
      result.current.toggleDepartment('IT');
      result.current.toggleSeverity('MILD');
    });

    act(() => {
      result.current.resetFilters();
    });

    expect(result.current.filters.departments).toEqual([]);
    expect(result.current.filters.severities).toEqual([]);
    expect(result.current.isDirty).toBe(false);
  });

  it('hasActiveFilters returns correct state', () => {
    const { result } = renderHook(() => useFilters());

    expect(result.current.hasActiveFilters()).toBe(false);

    act(() => {
      result.current.toggleDepartment('IT');
    });

    expect(result.current.hasActiveFilters()).toBe(true);
  });

  it('getFilterCount returns correct count', () => {
    const { result } = renderHook(() => useFilters());

    expect(result.current.getFilterCount()).toBe(0);

    act(() => {
      result.current.toggleDepartment('IT');
      result.current.toggleDepartment('HR');
      result.current.toggleSeverity('MILD');
    });

    expect(result.current.getFilterCount()).toBe(3);
  });

  it('saves filters to localStorage', () => {
    const { result } = renderHook(() => useFilters());

    act(() => {
      result.current.saveFilters('My Filter');
    });

    const saved = localStorage.getItem('saved-dashboard-filters');
    expect(saved).toBeTruthy();
    const parsed = JSON.parse(saved!);
    expect(parsed).toHaveLength(1);
    expect(parsed[0].name).toBe('My Filter');
    expect(result.current.savedFilters).toHaveLength(1);
  });

  it('loads saved filters', () => {
    const savedFilter = {
      id: 'test-id',
      name: 'Test Filter',
      filters: {
        dateRange: { start: new Date(), end: new Date() },
        departments: ['IT'],
        severities: [],
        diagnoses: [],
        employeeCodes: [],
      },
      createdAt: new Date(),
    };

    const { result } = renderHook(() => useFilters());

    act(() => {
      result.current.saveFilters('Test Filter');
    });

    act(() => {
      result.current.loadSavedFilter(savedFilter);
    });

    expect(result.current.filters.departments).toEqual(['IT']);
    expect(result.current.isDirty).toBe(false);
  });

  it('deletes saved filters', () => {
    const { result } = renderHook(() => useFilters());

    act(() => {
      result.current.saveFilters('Test Filter');
    });

    const id = result.current.savedFilters[0].id;

    act(() => {
      result.current.deleteSavedFilter(id);
    });

    expect(result.current.savedFilters).toHaveLength(0);
    const saved = localStorage.getItem('saved-dashboard-filters');
    expect(saved).toBeNull();
  });

  it('exports filters as JSON', () => {
    const { result } = renderHook(() => useFilters());

    act(() => {
      result.current.toggleDepartment('IT');
    });

    const exported = result.current.exportFilters();
    expect(() => JSON.parse(exported)).not.toThrow();
    const parsed = JSON.parse(exported);
    expect(parsed.departments).toContain('IT');
  });

  it('imports filters from JSON', () => {
    const { result } = renderHook(() => useFilters());

    const json = JSON.stringify({
      dateRange: { start: null, end: null },
      departments: ['IT', 'HR'],
      severities: [],
      diagnoses: [],
      employeeCodes: [],
    });

    const success = result.current.importFilters(json);

    expect(success).toBe(true);
    expect(result.current.filters.departments).toEqual(['IT', 'HR']);
  });
});

import { renderHook, act, waitFor } from '@testing-library/react';
import { useRealtimeUpdates } from '../useRealtimeUpdates';

class MockWebSocket {
  url: string;
  readyState: number = 0;
  onopen: ((event: Event) => void) | null = null;
  onmessage: ((event: MessageEvent) => void) | null = null;
  onerror: ((event: Event) => void) | null = null;
  onclose: ((event: CloseEvent) => void) | null = null;

  static CONNECTING = 0;
  static OPEN = 1;
  static CLOSING = 2;
  static CLOSED = 3;

  constructor(url: string) {
    this.url = url;
  }

  send(data: string): void {
    if (this.readyState !== MockWebSocket.OPEN) {
      throw new Error('WebSocket is not open');
    }
  }

  close(): void {
    this.readyState = MockWebSocket.CLOSED;
    this.onclose?.(new CloseEvent('close'));
  }
}

