      expect(result.current.connected).toBe(true);
    });

    act(() => {
      result.current.disconnect();
    });

    act(() => {
      jest.advanceTimersByTime(30);
    });

    expect(result.current.reconnectAttempts).toBe(2);
    expect(result.current.reconnecting).toBe(false);
