    const ws = global.WebSocket as any;
    const mockWs = ws.mock.instances[0];

    expect(() => {
      mockWs.send('test message');
    }).not.toThrow();
  });

  it('sends JSON messages when connected', async () => {
    const { result } = renderHook(() =>
      useRealtimeUpdates({
        url: 'ws://localhost:8080',
      })
    );

    await waitFor(() => {
      expect(result.current.connected).toBe(true);
    });

    act(() => {
      result.current.sendMessage({ type: 'ping' });
    });

    const ws = global.WebSocket as any;
    const mockWs = ws.mock.instances[0];

    expect(() => {
      mockWs.send('{"type":"ping"}');
    }).not.toThrow();
  });

  it('reconnects when called', async () => {
    const { result } = renderHook(() =>
      useRealtimeUpdates({
        url: 'ws://localhost:8080',
      })
    );

    await waitFor(() => {
      expect(result.current.connected).toBe(true);
    });

    act(() => {
      result.current.disconnect();
    });

    expect(result.current.connected).toBe(false);

    act(() => {
      result.current.reconnect();
    });

    await waitFor(() => {
      expect(result.current.connected).toBe(true);
    });
  });

  it('cleans up on unmount', () => {
    const { unmount } = renderHook(() =>
      useRealtimeUpdates({
        url: 'ws://localhost:8080',
      })
    );

    expect(() => unmount()).not.toThrow();
  });
});

import { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import api from '../services/api';

interface UseDashboardDataOptions {
  enabled?: boolean;
  refetchInterval?: number;
  onSuccess?: (data: unknown) => void;
  onError?: (error: Error) => void;
}

interface CacheEntry {
  data: unknown;
  timestamp: number;
}

const cache = new Map<string, CacheEntry>();

function getCacheKey(endpoint: string, params: Record<string, unknown>): string {
  return `${endpoint}?${JSON.stringify(params)}`;
}

function setCachedData(key: string, data: unknown): void {
  cache.set(key, { data, timestamp: Date.now() });
}

export function useDashboardData<T = unknown>(
  endpoint: string,
  params: Record<string, unknown> = {},
  options: UseDashboardDataOptions = {}
) {
  const {
    enabled = true,
    refetchInterval,
    onSuccess,
    onError,
  } = options;

  const [data, setData] = useState<T | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<Error | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);
  const isFetchingRef = useRef(false);

  const cacheKey = useMemo(() => getCacheKey(endpoint, params), [endpoint, params]);

  const fetchData = useCallback(async () => {
    if (!enabled || isFetchingRef.current) return;

    isFetchingRef.current = true;
    abortControllerRef.current?.abort();
    abortControllerRef.current = new AbortController();

    setIsLoading(true);
    setError(null);

    try {
      const response = await api.get<T>(endpoint, {
        params,
        signal: abortControllerRef.current.signal,
      });

      setData(response.data);
      setLastUpdated(new Date());
      setCachedData(cacheKey, response.data);
      onSuccess?.(response.data);
    } catch (err) {
      if (err instanceof Error && err.name !== 'AbortError') {
        const error = err as Error;
        setError(error);
        onError?.(error);
      }
    } finally {
      setIsLoading(false);
      isFetchingRef.current = false;
    }
  }, [endpoint, enabled, cacheKey, onSuccess, onError]);

  useEffect(() => {
    fetchData();

    return () => {
      abortControllerRef.current?.abort();
    };
  }, [fetchData]);

  useEffect(() => {
    if (refetchInterval && enabled) {
      const interval = setInterval(fetchData, refetchInterval);
      return () => clearInterval(interval);
    }
  }, [refetchInterval, fetchData, enabled]);

  const refetch = useCallback(() => {
    cache.delete(cacheKey);
    isFetchingRef.current = false;
    fetchData();
  }, [cacheKey, fetchData]);

  const invalidateCache = useCallback((key?: string) => {
    if (key) {
      cache.delete(key);
    } else {
      cache.clear();
    }
  }, []);

  return {
    data,
    isLoading,
    error,
    lastUpdated,
    refetch,
    invalidateCache,
  };
}

export function clearDashboardCache(): void {
  cache.clear();
}

import { useState, useCallback } from 'react';

export type ExportFormat = 'png' | 'svg' | 'pdf' | 'csv';

export interface ExportOptions {
  format: ExportFormat;
  quality?: number;
  filename?: string;
  includeTitle?: boolean;
  includeLegend?: boolean;
  backgroundColor?: string;
}

export function useExport() {
  const [isExporting, setIsExporting] = useState(false);
  const [exportProgress, setExportProgress] = useState(0);

  const exportChart = useCallback(async (
    elementId: string,
    options: ExportOptions = { format: 'png' }
  ): Promise<void> => {
    setIsExporting(true);
    setExportProgress(0);

    try {
      const element = document.getElementById(elementId);
      if (!element) {
        throw new Error('Element not found');
      }

      setExportProgress(20);

      const format = options.format;
      const filename = options.filename || `chart-export-${Date.now()}`;

      if (format === 'png' || format === 'svg') {
        setExportProgress(40);

        const html2canvas = (await import('html2canvas')).default;
        const canvas = await html2canvas(element, {
          backgroundColor: options.backgroundColor || '#ffffff',
          scale: (options.quality || 1) * 2,
          logging: false,
        });

        setExportProgress(80);

        const dataUrl = canvas.toDataURL(`image/${format}`);
        const link = document.createElement('a');
        link.download = `${filename}.${format}`;
        link.href = dataUrl;
        link.click();
      } else if (format === 'pdf') {
        setExportProgress(40);

        const html2canvas = (await import('html2canvas')).default;
        const canvas = await html2canvas(element, {
          backgroundColor: options.backgroundColor || '#ffffff',
          scale: 2,
          logging: false,
        });

        setExportProgress(60);

        const imgData = canvas.toDataURL('image/png');
        const { jsPDF } = await import('jspdf');
        const pdf = new jsPDF({
          orientation: canvas.width > canvas.height ? 'landscape' : 'portrait',
          unit: 'px',
          format: [canvas.width, canvas.height],
        });

        setExportProgress(80);

        pdf.addImage(imgData, 'PNG', 0, 0, canvas.width, canvas.height);
        pdf.save(`${filename}.pdf`);
      } else if (format === 'csv') {
        setExportProgress(60);

        const data = extractChartData(element);
        const csv = convertToCSV(data);
        downloadCSV(csv, `${filename}.csv`);
      }

      setExportProgress(100);
    } catch (error) {
      throw new Error(`Export failed: ${error instanceof Error ? error.message : 'Unknown error'}`);
    } finally {
      setIsExporting(false);
      setExportProgress(0);
    }
  }, []);

  const exportMultiple = useCallback(async (
    elements: Array<{ id: string; options?: ExportOptions }>
  ): Promise<void> => {
    setIsExporting(true);
    setExportProgress(0);

    const total = elements.length;

    try {
      for (let i = 0; i < total; i++) {
        const { id, options } = elements[i];
        await exportChart(id, options || { format: 'png' });
        setExportProgress(Math.round(((i + 1) / total) * 100));
      }
    } finally {
      setIsExporting(false);
      setExportProgress(0);
    }
  }, [exportChart]);

  const generateShareUrl = useCallback((
    currentUrl: string,
    params: Record<string, string>
  ): string => {
    const url = new URL(currentUrl);
    Object.entries(params).forEach(([key, value]) => {
      url.searchParams.set(key, value);
    });
    return url.toString();
  }, []);

  const copyToClipboard = useCallback(async (text: string): Promise<boolean> => {
    try {
      await navigator.clipboard.writeText(text);
      return true;
    } catch {
      return false;
    }
  }, []);

  return {
    isExporting,
    exportProgress,
    exportChart,
    exportMultiple,
    generateShareUrl,
    copyToClipboard,
  };
}

function extractChartData(element: HTMLElement): Array<Record<string, string>> {
  const data: Array<Record<string, string>> = [];

  const table = element.querySelector('table');
  if (table) {
    const headers = Array.from(table.querySelectorAll('th')).map((th) => th.textContent?.trim() || '');
    const rows = table.querySelectorAll('tbody tr');

    rows.forEach((row) => {
      const cells = Array.from(row.querySelectorAll('td'));
      const rowData: Record<string, string> = {};

      cells.forEach((cell, index) => {
        if (headers[index]) {
          rowData[headers[index]] = cell.textContent?.trim() || '';
        }
      });

      if (Object.keys(rowData).length > 0) {
        data.push(rowData);
      }
    });
  }

  return data;
}

function convertToCSV(data: Array<Record<string, string>>): string {
  if (data.length === 0) return '';

  const headers = Object.keys(data[0]);
  const headerRow = headers.join(',');
  const dataRows = data.map((row) =>
    headers.map((header) => {
      const value = row[header] || '';
      return `"${value.replace(/"/g, '""')}"`;
    }).join(',')
  );

  return [headerRow, ...dataRows].join('\n');
}

function downloadCSV(csv: string, filename: string): void {
  const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
  const link = document.createElement('a');
  link.href = URL.createObjectURL(blob);
  link.download = filename;
  link.click();
  URL.revokeObjectURL(link.href);
}

