import { useState, useEffect, useCallback, useRef } from 'react';

interface UseRealtimeUpdatesOptions {
  url: string;
  reconnectInterval?: number;
  maxReconnectAttempts?: number;
  onMessage?: (data: unknown) => void;
  onConnect?: () => void;
  onDisconnect?: () => void;
  onError?: (error: Event) => void;
}

interface WebSocketState {
  connected: boolean;
  reconnecting: boolean;
  reconnectAttempts: number;
}

export function useRealtimeUpdates(options: UseRealtimeUpdatesOptions) {
  const {
    url,
    reconnectInterval = 5000,
    maxReconnectAttempts = 5,
    onMessage,
    onConnect,
    onDisconnect,
    onError,
  } = options;

  const wsRef = useRef<WebSocket | null>(null);
  const reconnectTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const [state, setState] = useState<WebSocketState>({
    connected: false,
    reconnecting: false,
    reconnectAttempts: 0,
  });
  const [lastMessage, setLastMessage] = useState<unknown>(null);
  const [messageHistory, setMessageHistory] = useState<Array<{ time: Date; data: unknown }>>([]);
  const maxHistorySize = 100;

  const connect = useCallback(() => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      return;
    }

    try {
      wsRef.current = new WebSocket(url);
    } catch (error) {
      onError?.(error as Event);
      return;
    }

    wsRef.current.onopen = () => {
      setState((prev) => ({
        ...prev,
        connected: true,
        reconnecting: false,
        reconnectAttempts: 0,
      }));
      onConnect?.();
    };

    wsRef.current.onmessage = (event) => {
      try {
        const data = JSON.parse(event.data);
        setLastMessage(data);
        setMessageHistory((prev) => [
          { time: new Date(), data },
          ...prev.slice(0, maxHistorySize - 1),
        ]);
        onMessage?.(data);
      } catch {
        setLastMessage(event.data);
        setMessageHistory((prev) => [
          { time: new Date(), data: event.data },
          ...prev.slice(0, maxHistorySize - 1),
        ]);
        onMessage?.(event.data);
      }
    };

    wsRef.current.onerror = (error) => {
      onError?.(error);
    };

    wsRef.current.onclose = () => {
      setState((prev) => ({
        ...prev,
        connected: false,
      }));
      onDisconnect?.();

      if (state.reconnectAttempts < maxReconnectAttempts) {
        setState((prev) => ({
          ...prev,
          reconnecting: true,
          reconnectAttempts: prev.reconnectAttempts + 1,
        }));

        reconnectTimeoutRef.current = setTimeout(() => {
          connect();
        }, reconnectInterval);
      }
    };
  }, [url, reconnectInterval, maxReconnectAttempts, onConnect, onDisconnect, onError, onMessage, state.reconnectAttempts]);

  const disconnect = useCallback(() => {
    if (reconnectTimeoutRef.current) {
      clearTimeout(reconnectTimeoutRef.current);
    }
    if (wsRef.current) {
      wsRef.current.close();
      wsRef.current = null;
    }
    setState({
      connected: false,
      reconnecting: false,
      reconnectAttempts: 0,
    });
  }, []);

  const sendMessage = useCallback((data: string | Record<string, unknown>) => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      const message = typeof data === 'string' ? data : JSON.stringify(data);
      wsRef.current.send(message);
    }
  }, []);

  const reconnect = useCallback(() => {
    disconnect();
    setState((prev) => ({
      ...prev,
      reconnectAttempts: 0,
    }));
    connect();
  }, [disconnect, connect]);

  useEffect(() => {
    connect();

    return () => {
      disconnect();
    };
  }, [connect, disconnect]);

  return {
    connected: state.connected,
    reconnecting: state.reconnecting,
    reconnectAttempts: state.reconnectAttempts,
    lastMessage,
    messageHistory,
    sendMessage,
    disconnect,
    reconnect,
  };
}

import { describe, it, expect, vi, beforeEach } from 'vitest';
import axios from 'axios';
import type { AxiosError, InternalAxiosRequestConfig } from 'axios';

// We test the real module, so we need to isolate interceptor logic
// by extracting and testing handleApiError directly, and verifying
// the interceptor callbacks that were registered.

describe('api module', () => {
  beforeEach(() => {
    vi.restoreAllMocks();
    localStorage.clear();
  });

  describe('handleApiError', () => {
    // Import fresh each time to avoid module cache issues
    let handleApiError: (error: unknown) => string;

    beforeEach(async () => {
      const mod = await import('../api');
      handleApiError = mod.handleApiError;
    });

    it('extracts detail from axios error response', () => {
      const error = {
        isAxiosError: true,
        response: { data: { detail: 'Invalid credentials' }, status: 401 },
        message: 'Request failed',
      };
      // Patch axios.isAxiosError to recognize our mock
      vi.spyOn(axios, 'isAxiosError').mockReturnValue(true);
      expect(handleApiError(error)).toBe('Invalid credentials');
    });

    it('extracts first field error from validation errors', () => {
      const error = {
        isAxiosError: true,
        response: { data: { username: ['This field is required.'] }, status: 400 },
        message: 'Request failed',
      };
      vi.spyOn(axios, 'isAxiosError').mockReturnValue(true);
      expect(handleApiError(error)).toBe('This field is required.');
    });

    it('falls back to error.message when no response data', () => {
      const error = {
        isAxiosError: true,
        response: undefined,
        message: 'Network Error',
      };
      vi.spyOn(axios, 'isAxiosError').mockReturnValue(true);
      expect(handleApiError(error)).toBe('Network Error');
    });

    it('returns default message for non-axios errors', () => {
      vi.spyOn(axios, 'isAxiosError').mockReturnValue(false);
      expect(handleApiError(new Error('something'))).toBe('An unexpected error occurred');
    });

    it('returns default message for unknown error types', () => {
      vi.spyOn(axios, 'isAxiosError').mockReturnValue(false);
      expect(handleApiError('string error')).toBe('An unexpected error occurred');
    });

    it('handles response data with non-array field values', () => {
      const error = {
        isAxiosError: true,
        response: { data: { status: 'error' }, status: 400 },
        message: 'Bad Request',
      };
      vi.spyOn(axios, 'isAxiosError').mockReturnValue(true);
      // No detail, no array fields ΓåÆ falls through to message
      expect(handleApiError(error)).toBe('Bad Request');
    });
  });

  describe('api instance configuration', () => {
    it('creates instance with correct defaults', async () => {
      const { api } = await import('../api');
      expect(api.defaults.timeout).toBe(30000);
      expect(api.defaults.headers['Content-Type']).toBe('application/json');
    });
  });

  describe('request interceptor', () => {
    it('attaches Bearer token when token exists in localStorage', async () => {
      localStorage.setItem('access_token', 'test-jwt-token');
      const { api } = await import('../api');

      // Simulate the interceptor by getting the registered handler
      const config: InternalAxiosRequestConfig = {
        headers: new axios.AxiosHeaders(),
      } as InternalAxiosRequestConfig;

      // The interceptor is already registered, so we test through the instance
      // We can verify by checking if the interceptor manager has handlers
      expect(api.interceptors.request).toBeDefined();
    });
  });

  describe('response interceptor', () => {
    it('response interceptor is registered', async () => {
      const { api } = await import('../api');
      expect(api.interceptors.response).toBeDefined();
    });
  });
});

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { getEHSStatistics } from '../analytics';
import api from '../api';
import type { EHSStatistics } from '../../types';

vi.mock('../api');

describe('getEHSStatistics', () => {
  const mockEHSStatistics: EHSStatistics = {
    opd: {
      today_count: 5,
      till_date_count: 123,
      visits: [
        {
          id: '1',
          employee_code: 'EMP-001',
          employee_name: 'John Doe',
          department: 'Engineering',
          visit_time: '2026-05-24T09:30:00Z',
          chief_complaint: 'Headache',
          status: 'IN_PROGRESS',
        },
      ],
    },
    preEmployment: {
      total_checks: 48,
      fit_count: 45,
      unfit_count: 3,
      fit_rate: 93.75,
      today_count: 2,
    },
    ahc: {
      today_count: 2,
      till_date_count: 156,
      total_employees: 233,
      completion_percentage: 66.95,
    },
    incident: {
      today_count: 0,
      till_date_count: 12,
      severity: { LOW: 7, MEDIUM: 3, HIGH: 2, CRITICAL: 0 },
      attention_required: false,
    },
    emergency: {
      today_count: 1,
      till_date_count: 8,
      severity: { LOW: 1, MEDIUM: 2, HIGH: 3, CRITICAL: 2 },
      critical_alert: true,
    },
    referred: {
      today_count: 0,
      till_date_count: 23,
      hospitals: [
        { hospital_name: 'City Hospital', referral_count: 12 },
        { hospital_name: 'MediCare Clinic', referral_count: 8 },
      ],
    },
  };

  beforeEach(() => {
    vi.clearAllMocks();
  });

  describe('Success Cases', () => {
    it('should fetch EHS statistics successfully', async () => {
      vi.mocked(api.get).mockResolvedValue({
        data: mockEHSStatistics,
      } as any);

      const result = await getEHSStatistics();

      expect(api.get).toHaveBeenCalledWith('/ohc/analytics/ehs-statistics/', {
        params: undefined,
      });
      expect(result).toEqual(mockEHSStatistics);
    });

    it('should pass query parameters to the API', async () => {
      const filters = {
        date_from: '2026-05-01',
        date_to: '2026-05-31',
        department: 'Engineering',
      };

      vi.mocked(api.get).mockResolvedValue({
        data: mockEHSStatistics,
      } as any);

      await getEHSStatistics(filters);

      expect(api.get).toHaveBeenCalledWith('/ohc/analytics/ehs-statistics/', {
        params: filters,
      });
    });
  });

  describe('Error Handling', () => {
    it('should throw an error when API request fails', async () => {
      const mockError = new Error('Network error');
      vi.mocked(api.get).mockRejectedValue(mockError);

      await expect(getEHSStatistics()).rejects.toThrow('Network error');
    });

    it('should throw an error with error message when response contains error', async () => {
      vi.mocked(api.get).mockRejectedValue({
        response: { data: { detail: 'Authentication failed' } },
      });

      await expect(getEHSStatistics()).rejects.toThrow();
    });
  });

  describe('Data Validation', () => {
    it('should return valid OPD statistics', async () => {
      vi.mocked(api.get).mockResolvedValue({
        data: mockEHSStatistics,
      } as any);

      const result = await getEHSStatistics();

      expect(result.opd.today_count).toBeGreaterThanOrEqual(0);
      expect(result.opd.visits).toBeInstanceOf(Array);
      expect(result.opd.visits[0]).toHaveProperty('employee_name');
      expect(result.opd.visits[0]).toHaveProperty('department');
      expect(result.opd.visits[0]).toHaveProperty('visit_time');
    });

    it('should return valid pre-employment statistics', async () => {
      vi.mocked(api.get).mockResolvedValue({
        data: mockEHSStatistics,
      } as any);

      const result = await getEHSStatistics();

      expect(result.preEmployment.fit_count + result.preEmployment.unfit_count).toBeLessThanOrEqual(
        result.preEmployment.total_checks
      );
      expect(result.preEmployment.fit_rate).toBeGreaterThanOrEqual(0);
      expect(result.preEmployment.fit_rate).toBeLessThanOrEqual(100);
    });

    it('should return valid AHC statistics', async () => {
      vi.mocked(api.get).mockResolvedValue({
        data: mockEHSStatistics,
      } as any);

      const result = await getEHSStatistics();

      expect(result.ahc.till_date_count).toBeLessThanOrEqual(result.ahc.total_employees);
      expect(result.ahc.completion_percentage).toBeGreaterThanOrEqual(0);
      expect(result.ahc.completion_percentage).toBeLessThanOrEqual(100);
    });

    it('should return valid incident statistics with severity breakdown', async () => {
      vi.mocked(api.get).mockResolvedValue({
        data: mockEHSStatistics,
      } as any);

      const result = await getEHSStatistics();

      expect(result.incident.severity).toHaveProperty('LOW');
      expect(result.incident.severity).toHaveProperty('MEDIUM');
      expect(result.incident.severity).toHaveProperty('HIGH');
      expect(result.incident.severity).toHaveProperty('CRITICAL');
      expect(
        Object.values(result.incident.severity).reduce((sum, count) => sum + count, 0)
      ).toBe(result.incident.till_date_count);
    });

    it('should return valid emergency statistics', async () => {
      vi.mocked(api.get).mockResolvedValue({
        data: mockEHSStatistics,
      } as any);

      const result = await getEHSStatistics();

      expect(result.emergency.critical_alert).toBe(result.emergency.today_count > 0);
      expect(
        Object.values(result.emergency.severity).reduce((sum, count) => sum + count, 0)
      ).toBe(result.emergency.till_date_count);
    });

    it('should return valid referred statistics', async () => {
      vi.mocked(api.get).mockResolvedValue({
        data: mockEHSStatistics,
      } as any);

      const result = await getEHSStatistics();

      expect(result.referred.hospitals).toBeInstanceOf(Array);
      if (result.referred.hospitals.length > 0) {
        expect(result.referred.hospitals[0]).toHaveProperty('hospital_name');
        expect(result.referred.hospitals[0]).toHaveProperty('referral_count');
      }
    });
  });
});

import api from './api';

/**
 * Medicine Stock API Service
 * Handles all medicine inventory operations
 */

interface MedicineStockListParams {
  search?: string;
  low_stock_only?: boolean;
  expiring_soon?: boolean;
  page?: number;
  page_size?: number;
}

interface DispenseMedicineData {
  visit_id?: number;
  prescription_id?: number;
  quantity_dispensed: number;
  issue_date: string;
  remarks?: string;
}

interface DispenseResponse {
  medicine_id: number;
  medicine_name: string;
  quantity_before: number;
  quantity_dispensed: number;
  quantity_remaining: number;
  issue_date: string;
  remarks: string;
  message: string;
}

interface LowStockMedicine {
  id: number;
  medicine_id: string;
  name: string;
  stock_quantity: number;
  unit: string;
  initial_stock: number;
  used_quantity: number;
  supplier?: string;
  batch_number?: string;
  expiry_date?: string;
  reorder_level: number;
  last_dispensed_at?: string;
  is_low_stock: boolean;
  is_expired: boolean;
  is_expiring_soon: boolean;
  created_at: string;
  updated_at: string;
}

interface MedicineHistory {
  medicine: LowStockMedicine;
  history: LowStockMedicine[];
}

/**
 * Medicine Stock Service
 * Provides methods to interact with medicine inventory
 */
export const listMedicines = async (
  params?: MedicineStockListParams
): Promise<{ results: any[] }> => {
  const queryParams: any = {};

  if (params?.search) queryParams.search = params.search;
  if (params?.low_stock_only) queryParams.low_stock_only = params.low_stock_only;
  if (params?.expiring_soon) queryParams.expiring_soon = params.expiring_soon;
  if (params?.page) queryParams.page = params.page;
  if (params?.page_size) queryParams.page_size = params.page_size;

  const response = await api.get('/ohc/medicines/', { params: queryParams });
  return response.data;
};

export const dispenseMedicine = async (medicineId: number, data: DispenseMedicineData): Promise<DispenseResponse> => {
  const response = await api.post(`/ohc/medicines/${medicineId}/dispense/`, data);
  return response.data;
};

/**
 * Get all medicines with optional filtering
 */
export const medicineService = {
  listMedicines,

  /**
   * Get medicine by ID
   */
  getMedicine: async (id: number): Promise<LowStockMedicine> => {
    const response = await api.get(`/ohc/medicines/${id}/`);
    return response.data;
  },

  /**
   * Create new medicine entry
   */
  createMedicine: async (data: any): Promise<LowStockMedicine> => {
    const response = await api.post('/ohc/medicines/', data);
    return response.data;
  },

  /**
   * Dispense medicine to patient
   * Updates stock and creates dispensing record
   */
  dispenseMedicine: async (medicineId: number, data: DispenseMedicineData): Promise<DispenseResponse> => {
    const response = await api.post(`/ohc/medicines/${medicineId}/dispense/`, data);
    return response.data;
  },

  /**
   * Get medicine dispensing history
   */
  getMedicineHistory: async (id: number): Promise<MedicineHistory> => {
    const response = await api.get(`/ohc/medicines/${id}/history/`);
    return response.data;
  },

  /**
   * Get low stock medicines
   */
  getLowStockMedicines: async (): Promise<LowStockMedicine[]> => {
    const response = await api.get('/ohc/medicines/', { params: { low_stock_only: true } });
    return response.data.results?.filter((medicine: any) => medicine.is_low_stock) || [];
  },

  /**
   * Get expiring soon medicines
   */
  getExpiringSoonMedicines: async (): Promise<LowStockMedicine[]> => {
    const response = await api.get('/ohc/medicines/', { params: { expiring_soon: true } });
    return response.data.results?.filter((medicine: any) => medicine.is_expiring_soon) || [];
  },

  /**
   * Get medicine statistics summary
   */
  getMedicineStatistics: async (): Promise<{
    total_medicines: number;
    total_stock_quantity: number;
    total_medicine_used: number;
    total_medicine_value: number;
    stock_summary: {
      total_items: number;
      low_stock_items: number;
      expiring_items: number;
      total_stock_value: number;
    };
  }> => {
    const response = await api.get('/ohc/analytics/medicine-summary/');
    return response.data;
  },

  /**
   * Get department health trends for management
   */
  getDepartmentHealthTrends: async (): Promise<any> => {
    const response = await api.get('/ohc/analytics/medicine-summary/');
    return response.data.department_health_trends;
  },
};

export default medicineService;

import api, { handleApiError } from './api';
import type {
  OHCVisit,
  OHCVisitFormData,
  Diagnosis,
  DiagnosisFormData,
  Prescription,
  PaginatedResponse,
} from '../types';

/**
 * List OHC visits with optional filters
 * @param params - Query parameters for filtering
 * @returns Promise resolving to paginated visits
 */
export const listVisits = async (params?: {
  employee?: string;
  status?: string;
  date_from?: string;
  date_to?: string;
  page?: number;
  page_size?: number;
}): Promise<PaginatedResponse<OHCVisit>> => {
  try {
    const response = await api.get<PaginatedResponse<OHCVisit>>('/ohc/visits/', { params });
    return response.data;
  } catch (error) {
    throw new Error(handleApiError(error), { cause: error });
  }
};

/**
 * Get a single OHC visit by UUID
 * @param uuid - Visit UUID
 * @returns Promise resolving to visit data
 */
export const getVisit = async (uuid: string): Promise<OHCVisit> => {
  try {
    const response = await api.get<OHCVisit>(`/ohc/visits/${uuid}/`);
    return response.data;
  } catch (error) {
    throw new Error(handleApiError(error), { cause: error });
  }
};

/**
 * Create a new OHC visit
 * @param data - Visit form data
 * @returns Promise resolving to created visit
 */
export const createVisit = async (data: OHCVisitFormData): Promise<OHCVisit> => {
  try {
    const response = await api.post<OHCVisit>('/ohc/visits/', data);
    return response.data;
  } catch (error) {
    throw new Error(handleApiError(error), { cause: error });
  }
};

/**
 * Create diagnosis with associated prescriptions
 * @param data - Diagnosis form data with prescriptions
 * @returns Promise resolving to created diagnosis, prescriptions, and updated visit status
 */
export const createDiagnosis = async (data: DiagnosisFormData): Promise<{
  diagnosis: Diagnosis;
  prescriptions: Prescription[];
  referral?: {
    id: number;
    referral_status: string;
    priority: string;
  };
  visit_status: string;
  follow_up_date?: string;
  next_action?: string;
}> => {
  try {
    const response = await api.post('/ohc/diagnosis-prescriptions/', data);
    return response.data;
  } catch (error) {
    throw new Error(handleApiError(error), { cause: error });
  }
};

/**
 * Get diagnoses for a specific visit
 * @param visitUuid - Visit UUID
 * @returns Promise resolving to array of diagnoses
 */
export const getVisitDiagnoses = async (visitUuid: string): Promise<Diagnosis[]> => {
  try {
    const response = await api.get<Diagnosis[]>(`/ohc/visits/${visitUuid}/diagnoses/`);
    return response.data;
  } catch (error) {
    throw new Error(handleApiError(error), { cause: error });
  }
};

/**
 * Get prescriptions for a specific visit
 * @param visitUuid - Visit UUID
 * @returns Promise resolving to array of prescriptions
 */
export const getVisitPrescriptions = async (visitUuid: string): Promise<Prescription[]> => {
  try {
    const response = await api.get<Prescription[]>(`/ohc/visits/${visitUuid}/prescriptions/`);
    return response.data;
  } catch (error) {
    throw new Error(handleApiError(error), { cause: error });
  }
};

/**
 * Get pending prescriptions for pharmacist
 * @returns Promise resolving to array of prescriptions with visit and medicine details
 */
export const getPharmacistPrescriptions = async (): Promise<any[]> => {
  try {
    const response = await api.get('/ohc/prescriptions/');
    return response.data;
  } catch (error) {
    throw new Error(handleApiError(error), { cause: error });
  }
};

export const getPreEmploymentPharmacistSummary = async (): Promise<{
  doctor_completed_without_medicines: number;
}> => {
  try {
    const response = await api.get('/ohc/prescriptions/pre-employment-summary/');
    return response.data;
  } catch (error) {
    throw new Error(handleApiError(error), { cause: error });
  }
};

/**
 * Update visit status
 * @param visitId - Visit ID
 * @param status - New visit status
 * @returns Promise resolving to updated visit
 */
export const updateVisitStatus = async (visitId: number, status: string): Promise<OHCVisit> => {
  try {
    const response = await api.patch<OHCVisit>(`/ohc/visits/${visitId}/`, { visit_status: status });
    return response.data;
  } catch (error) {
    throw new Error(handleApiError(error), { cause: error });
  }
};

import React from 'react';

// Create a mock wrapper for Recharts components that causes timeout issues
export const MockResponsiveContainer: React.FC<{ children: React.ReactNode; width?: string | number; height?: string | number }> = ({
  children,
  width = '100%',
  height = '100%',
}) => (
  <div style={{ width, height }} data-testid="recharts-responsive-container">
    {children}
  </div>
);

// Mock PieChart
export const MockPieChart: React.FC<{ children: React.ReactNode; data?: any[]; margin?: any }> = ({ children }) => (
  <svg data-testid="recharts-pie-chart">{children}</svg>
);

// Mock Pie
export const MockPie: React.FC<{
  children?: React.ReactNode;
  data?: any[];
  cx?: string | number;
  cy?: string | number;
  labelLine?: boolean;
  label?: any;
  outerRadius?: number;
  innerRadius?: number;
  paddingAngle?: number;
  dataKey?: string;
  name?: string;
}> = ({ children, data, label }) => {
  // Only render children if data exists (simplifies testing)
  return (
    <g data-testid="recharts-pie" data-has-data={data && data.length > 0}>
      {children}
      {/* If label is a component and has data, call it */}
      {label && data && data.length > 0 && React.createElement(label, { viewBox: { cx: 200, cy: 200 } })}
    </g>
  );
};

// Mock Cell
export const MockCell: React.FC<{ fill?: string; key?: string }> = ({ fill }) => (
  <circle r="10" fill={fill} data-testid="recharts-cell" />
);

// Mock BarChart
export const MockBarChart: React.FC<{ children: React.ReactNode; data?: any[]; margin?: any }> = ({ children }) => (
  <svg data-testid="recharts-bar-chart">{children}</svg>
);

