import { format, parseISO, differenceInDays, subDays } from 'date-fns';

/**
 * Chart data types for Employee Health History
 */

export interface VisitFrequencyData {
  date: string;
  fullDate: string;
  count: number;
}

export interface VisitTypeData {
  type: 'Routine' | 'Walk-in' | 'Follow-up';
  count: number;
  percentage: number;
}

export interface DiagnosisDistributionData {
  name: string;
  count: number;
  percentage: number;
  color: string;
}

export interface SeverityBreakdownData {
  severity: 'MILD' | 'MODERATE' | 'SERIOUS' | 'CRITICAL';
  count: number;
  color: string;
}

export interface HealthIndexTrendData {
  date: string;
  fullDate: string;
  healthIndex: number;
  status: 'good' | 'warning' | 'concern';
}

export interface QuickStatsData {
  totalVisits: number;
  avgRecoveryTime: number;
  fitnessTrend: {
    direction: 'up' | 'down' | 'stable';
    percentage: number;
  };
}

export interface TransformedChartData {
  summary: {
    employeeName: string;
    department: string;
    designation: string;
    fitnessStatus: string;
    healthScore: number;
    totalVisits: number;
    avgRecoveryTime: number;
    fitnessTrend: QuickStatsData['fitnessTrend'];
  };
  visitFrequency: VisitFrequencyData[];
  visitTypes: VisitTypeData[];
  diagnosisDistribution: DiagnosisDistributionData[];
  severityBreakdown: SeverityBreakdownData[];
  healthIndexTrend: HealthIndexTrendData[];
}

// Color palettes
export const DIAGNOSIS_COLORS = [
  '#3b82f6',
  '#10b981',
  '#f59e0b',
  '#8b5cf6',
  '#06b6d4',
  '#ec4899',
  '#f97316',
] as const;

export const SEVERITY_COLORS: Record<string, string> = {
  MILD: '#10b981',
  MODERATE: '#f59e0b',
  SERIOUS: '#f97316',
  CRITICAL: '#ef4444',
} as const;

export const CHART_COLORS = DIAGNOSIS_COLORS;

/**
 * Transform raw API data into chart-ready format
 */
export function transformEmployeeHealthHistory(
  apiData: any,
  dailyMonthly: 'daily' | 'monthly'
): TransformedChartData {
  const { visits } = apiData;

  return {
    summary: transformSummary(apiData),
    visitFrequency: transformVisitFrequency(visits, dailyMonthly),
    visitTypes: transformVisitTypes(visits),
    diagnosisDistribution: transformDiagnosisDistribution(visits, 5),
    severityBreakdown: transformSeverityBreakdown(visits),
    healthIndexTrend: transformHealthIndexTrend(visits, dailyMonthly),
  };
}

/**
 * Transform summary data
 */
function transformSummary(apiData: any) {
  const { employee, visits } = apiData;

  const healthScore = calculateHealthScore(visits, employee.fitness_status);
  const totalVisits = visits.length;
  const avgRecoveryTime = calculateAvgRecoveryTime(visits);
  const fitnessTrend = calculateFitnessTrend(visits);

  return {
    employeeName: `${employee.user.first_name} ${employee.user.last_name}`,
    department: employee.department,
    designation: employee.designation,
    fitnessStatus: employee.fitness_status,
    healthScore,
    totalVisits,
    avgRecoveryTime,
    fitnessTrend,
  };
}

/**
 * Calculate health score (0-100)
 */
export function calculateHealthScore(visits: any[], fitnessStatus: string): number {
  let score = 100;

  // Base score from fitness status
  switch (fitnessStatus) {
    case 'FIT':
      score = 90;
      break;
    case 'TEMPORARY_UNFIT':
      score = 70;
      break;
    case 'UNDER_OBSERVATION':
      score = 60;
      break;
    case 'UNFIT':
      score = 30;
      break;
  }

  // Adjust based on recent visits (last 90 days)
  const now = new Date();
  const recentVisits = visits.filter((v) => {
    const visitDate = parseISO(v.visit_date);
    return differenceInDays(now, visitDate) <= 90;
  });

  const severityDeductions = recentVisits.reduce((sum, visit) => {
    const maxSeverity = getMaxSeverityFromDiagnoses(visit.diagnoses);
    switch (maxSeverity) {
      case 'CRITICAL':
        return sum - 15;
      case 'SERIOUS':
        return sum - 10;
      case 'MODERATE':
        return sum - 5;
      case 'MILD':
        return sum - 2;
      default:
        return sum;
    }
  }, 0);

  score += severityDeductions;
  return Math.max(0, Math.min(100, score));
}

/**
 * Get maximum severity from diagnoses array
 */
function getMaxSeverityFromDiagnoses(diagnoses: any[]): string {
  if (!diagnoses || diagnoses.length === 0) return 'MILD';

  const severityOrder = ['CRITICAL', 'SERIOUS', 'MODERATE', 'MILD'];
  const severities = diagnoses.map((d) => d.severity).filter(Boolean);

  for (const level of severityOrder) {
    if (severities.includes(level)) return level;
  }

  return 'MILD';
}

/**
 * Calculate average recovery time in days
 */
function calculateAvgRecoveryTime(visits: any[]): number {
  if (visits.length < 2) return 0;

  const sorted = [...visits].sort(
    (a, b) => new Date(a.visit_date).getTime() - new Date(b.visit_date).getTime()
  );

  let totalDays = 0;
  for (let i = 1; i < sorted.length; i++) {
    const days = differenceInDays(
      parseISO(sorted[i].visit_date),
      parseISO(sorted[i - 1].visit_date)
    );
    totalDays += days;
  }

  return Math.round(totalDays / (sorted.length - 1));
}

/**
 * Calculate fitness trend
 */
function calculateFitnessTrend(visits: any[]): QuickStatsData['fitnessTrend'] {
  const now = new Date();
  const recentStart = subDays(now, 30);
  const previousEnd = recentStart;
  const previousStart = subDays(previousEnd, 30);

  const recentVisits = visits.filter((v) => {
    const visitDate = parseISO(v.visit_date);
    return visitDate >= recentStart && visitDate <= now;
  });
  const previousVisits = visits.filter((v) => {
    const visitDate = parseISO(v.visit_date);
    return visitDate >= previousStart && visitDate < recentStart;
  });

  const recentAvg = calculateHealthScore(recentVisits, 'FIT');
  const previousAvg = calculateHealthScore(previousVisits, 'FIT');

  const diff = recentAvg - previousAvg;
  const percentage = previousAvg > 0 ? (diff / previousAvg) * 100 : 0;

  if (percentage > 5) return { direction: 'up' as const, percentage: Math.abs(percentage) };
  if (percentage < -5) return { direction: 'down' as const, percentage: Math.abs(percentage) };
  return { direction: 'stable' as const, percentage: Math.abs(percentage) };
}

/**
 * Transform visit frequency data
 */
export function transformVisitFrequency(
  visits: any[],
  dailyMonthly: 'daily' | 'monthly'
): VisitFrequencyData[] {
  const grouped: Record<string, number> = {};

  visits.forEach((visit) => {
    const date = parseISO(visit.visit_date);
    let key: string;

    if (dailyMonthly === 'daily') {
      key = date.toISOString().split('T')[0];
    } else {
      key = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
    }

    grouped[key] = (grouped[key] || 0) + 1;
  });

  return Object.entries(grouped)
    .map(([date, count]) => ({
      date: dailyMonthly === 'daily' ? format(parseISO(date), 'MMM dd') : format(parseISO(date), 'MMM yyyy'),
      fullDate: date,
      count,
    }))
    .sort((a, b) => new Date(a.fullDate).getTime() - new Date(b.fullDate).getTime());
}

/**
 * Transform visit types data
 */
export function transformVisitTypes(visits: any[]): VisitTypeData[] {
  const counts: Record<string, number> = {
    Routine: 0,
    'Walk-in': 0,
    'Follow-up': 0,
  };

  visits.forEach((visit) => {
    const type = mapVisitType(visit.visit_type);
    counts[type] = (counts[type] || 0) + 1;
  });

  const total = visits.length;

  return Object.entries(counts).map(([type, count]) => ({
    type: type as 'Routine' | 'Walk-in' | 'Follow-up',
    count,
    percentage: total > 0 ? Math.round((count / total) * 100) : 0,
  }));
}

/**
 * Map API visit type to display type
 */
function mapVisitType(apiType: string): string {
  const mapping: Record<string, string> = {
    ROUTINE: 'Routine',
    WALK_IN: 'Walk-in',
    FOLLOW_UP: 'Follow-up',
    PERIODIC: 'Routine',
    PRE_EMPLOYMENT: 'Routine',
    EMERGENCY: 'Walk-in',
  };
  return mapping[apiType] || 'Routine';
}

/**
 * Transform diagnosis distribution data
 */
export function transformDiagnosisDistribution(
  visits: any[],
  maxItems: number = 5
): DiagnosisDistributionData[] {
  const counts: Record<string, number> = {};

  visits.forEach((visit) => {
    visit.diagnoses?.forEach((diagnosis: any) => {
      const name = diagnosis.diagnosis_name;
      counts[name] = (counts[name] || 0) + 1;
    });
  });

  const sorted = Object.entries(counts).sort((a, b) => b[1] - a[1]);
  const totalVisits = visits.reduce((sum, v) => sum + (v.diagnoses?.length || 0), 0);

  const topItems = sorted.slice(0, maxItems);
  const otherCount = sorted.slice(maxItems).reduce((sum, [, count]) => sum + count, 0);

  const result: DiagnosisDistributionData[] = topItems.map(([name, count], index) => ({
    name,
    count,
    percentage: totalVisits > 0 ? Math.round((count / totalVisits) * 100) : 0,
    color: DIAGNOSIS_COLORS[index % DIAGNOSIS_COLORS.length],
  }));

  if (otherCount > 0) {
    result.push({
      name: 'Other',
      count: otherCount,
      percentage: totalVisits > 0 ? Math.round((otherCount / totalVisits) * 100) : 0,
      color: '#9ca3af',
    });
  }

  return result;
}

/**
 * Transform severity breakdown data
 */
export function transformSeverityBreakdown(visits: any[]): SeverityBreakdownData[] {
  const counts: Record<string, number> = {
    MILD: 0,
    MODERATE: 0,
    SERIOUS: 0,
    CRITICAL: 0,
  };

  visits.forEach((visit) => {
    visit.diagnoses?.forEach((diagnosis: any) => {
      const severity = diagnosis.severity;
      if (severity) {
        counts[severity] = (counts[severity] || 0) + 1;
      }
    });
  });

  const severityOrder: Array<keyof typeof counts> = ['MILD', 'MODERATE', 'SERIOUS', 'CRITICAL'];
  return severityOrder.map((severity) => ({
    severity,
    count: counts[severity],
    color: SEVERITY_COLORS[severity],
  })) as SeverityBreakdownData[];
}

/**
 * Transform health index trend data
 */
function transformHealthIndexTrend(
  visits: any[],
  dailyMonthly: 'daily' | 'monthly'
): HealthIndexTrendData[] {
  const groupedVisits: Record<string, any[]> = {};

  visits.forEach((visit) => {
    const date = parseISO(visit.visit_date);
    let key: string;

    if (dailyMonthly === 'daily') {
      key = date.toISOString().split('T')[0];
    } else {
      key = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
    }

    groupedVisits[key] = groupedVisits[key] || [];
    groupedVisits[key].push(visit);
  });

  const result: HealthIndexTrendData[] = [];
  const sortedKeys = Object.keys(groupedVisits).sort();

  sortedKeys.forEach((dateKey) => {
    const periodDate = parseISO(dateKey);

    const contextVisits = visits.filter((visit) => {
      const visitDate = parseISO(visit.visit_date);
      const daysDiff = differenceInDays(periodDate, visitDate);
      return daysDiff >= 0 && daysDiff <= 30;
    });

    const healthIndex = calculateHealthScore(contextVisits, 'FIT');
    const status = healthIndex >= 80 ? 'good' : healthIndex >= 60 ? 'warning' : 'concern';

    result.push({
      date: dailyMonthly === 'daily' ? format(periodDate, 'MMM dd') : format(periodDate, 'MMM yyyy'),
      fullDate: dateKey,
      healthIndex: Math.round(healthIndex),
      status,
    });
  });

  return result;
}

/**
 * Chart data transformation utilities
 * Converts API responses to chart-compatible data formats
 */

// ============================================================================
// Type Definitions
// ============================================================================

export interface VisitTrendData {
  date: Date;
  count: number;
}

export interface DepartmentComparisonData {
  department: string;
  visits: number;
  employees: number;
  referrals: number;
}

export interface SeverityData {
  severity: 'MILD' | 'MODERATE' | 'SEVERE' | 'CRITICAL';
  count: number;
  color: string;
  percentage?: number;
}

export interface DiagnosisTrendData {
  diagnosis: string;
  data: VisitTrendData[];
  color: string;
}

export interface HealthIndexData {
  department: string;
  healthIndex: number;
  visits: number;
  referrals: number;
  unfit: number;
  employees: number;
}

export interface VisitsReferralsData {
  department: string;
  visits: number;
  referrals: number;
}

export interface DiagnosisAreaData {
  diagnosis: string;
  data: VisitTrendData[];
  color: string;
  severity?: string;
}

export interface SeverityTrendData {
  severity: string;
  data: VisitTrendData[];
  color: string;
}

// ============================================================================
// Color Helpers
// ============================================================================

const SEVERITY_COLORS: Record<string, string> = {
  MILD: '#10b981',
  MODERATE: '#f59e0b',
  SEVERE: '#f97316',
  CRITICAL: '#ef4444',
};

const DIAGNOSIS_COLORS = [
  '#3b82f6', // Blue
  '#10b981', // Green
  '#f59e0b', // Yellow
  '#ef4444', // Red
  '#8b5cf6', // Purple
  '#06b6d4', // Cyan
  '#ec4899', // Pink
  '#84cc16', // Lime
  '#6366f1', // Indigo
  '#14b8a6', // Teal
];

/**
 * Get color for severity level
 */
export function getSeverityColor(severity: string): string {
  return SEVERITY_COLORS[severity] || '#6b7280';
}

/**
 * Get color for diagnosis (consistent based on name)
 */
export function getDiagnosisColor(diagnosis: string): string {
  // Hash-based color generation for consistency
  const hash = diagnosis.split('').reduce((acc, char) => acc + char.charCodeAt(0), 0);
  return DIAGNOSIS_COLORS[hash % DIAGNOSIS_COLORS.length];
}

/**
 * Get color for health index
 */
export function getHealthIndexColor(index: number): string {
  if (index >= 80) return '#10b981'; // Green
  if (index >= 60) return '#f59e0b'; // Yellow
  return '#ef4444'; // Red
}

// ============================================================================
// Dashboard Data Transformers
// ============================================================================

/**
 * Transform dashboard API response to chart data
 */
export function transformDashboardData(apiResponse: any): {
  visitTrends: VisitTrendData[];
  departmentComparison: DepartmentComparisonData[];
  severityBreakdown: SeverityData[];
  diagnosisTrends: DiagnosisTrendData[];
} {
  const visitTrends: VisitTrendData[] = (apiResponse.visit_trends || []).map(
    (item: any) => ({
      date: new Date(item.date),
      count: item.count,
    })
  );

  const departmentComparison: DepartmentComparisonData[] = (
    apiResponse.department_comparison || []
  ).map((item: any) => ({
    department: item.department,
    visits: item.visits,
    employees: item.employees,
    referrals: item.referrals,
  }));

  const severityBreakdown: SeverityData[] = Object.entries(
    apiResponse.severity_breakdown || {}
  ).map(([severity, count]: [string, any]) => ({
    severity: severity as any,
    count: count as number,
    color: getSeverityColor(severity),
  }));

  const diagnosisTrends: DiagnosisTrendData[] = (
    apiResponse.common_diagnoses || []
  )
    .slice(0, 5)
    .map((item: any) => ({
      diagnosis: item.diagnosis_name,
      data: (item.trend || []).map((t: any) => ({
        date: new Date(t.date),
        count: t.count,
      })),
      color: getDiagnosisColor(item.diagnosis_name),
    }));

  return {
    visitTrends,
    departmentComparison,
    severityBreakdown,
    diagnosisTrends,
  };
}

// ============================================================================
// Department Stats Data Transformers
// ============================================================================

/**
 * Transform department stats API response to chart data
 */
export function transformDepartmentStatsData(apiResponse: any): {
  healthIndex: HealthIndexData[];
  visitsReferrals: VisitsReferralsData[];
} {
  const healthIndex: HealthIndexData[] = (apiResponse.departments || []).map(
    (dept: any) => ({
      department: dept.department,
      healthIndex: dept.health_index,
      visits: dept.total_visits,
      referrals: dept.referred_cases,
      unfit: dept.unfit_employees,
      employees: dept.total_employees,
    })
  );

  const visitsReferrals: VisitsReferralsData[] = (apiResponse.departments || []).map(
    (dept: any) => ({
      department: dept.department,
      visits: dept.total_visits,
      referrals: dept.referred_cases,
    })
  );

  return {
    healthIndex,
    visitsReferrals,
  };
}

// ============================================================================
// Disease Trends Data Transformers
// ============================================================================

/**
 * Transform disease trends API response to chart data
 */
export function transformDiseaseTrendsData(apiResponse: any): {
  diagnosisArea: DiagnosisAreaData[];
  severityTrends: SeverityTrendData[];
} {
  const diagnosisArea: DiagnosisAreaData[] = (apiResponse.trends || [])
    .slice(0, 5)
    .map((item: any) => ({
      diagnosis: item.diagnosis_name,
      data: (item.trend_data || []).map((t: any) => ({
        date: new Date(t.date),
        count: t.count,
      })),
      color: getDiagnosisColor(item.diagnosis_name),
      severity: item.severity,
    }));

  const severityTrends: SeverityTrendData[] = Object.entries(
    apiResponse.severity_trends || {}
  ).map(([severity, data]: [string, any]) => ({
    severity,
    data: (data || []).map((t: any) => ({
      date: new Date(t.date),
      count: t.count,
    })),
    color: getSeverityColor(severity),
  }));

  return {
    diagnosisArea,
    severityTrends,
  };
}

// ============================================================================
// Data Aggregation Helpers
// ============================================================================

/**
 * Aggregate data by period (daily/monthly)
 */
export function aggregateByPeriod(
  data: Array<{ date: Date; count: number }>,
  period: 'daily' | 'monthly'
): Array<{ date: Date; count: number }> {
  if (period === 'daily') {
    return data;
  }

  // Monthly aggregation
  const monthlyData: Record<string, number> = {};

  data.forEach((item) => {
    const date = item.date;
    const monthKey = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
    monthlyData[monthKey] = (monthlyData[monthKey] || 0) + item.count;
  });

  return Object.entries(monthlyData).map(([month, count]) => ({
    date: new Date(`${month}-01`),
    count,
  }));
}

/**
 * Calculate percentage from total
 */
export function calculatePercentage(value: number, total: number): number {
  if (total === 0) return 0;
  return Math.round((value / total) * 100 * 10) / 10; // Round to 1 decimal
}

// ============================================================================
// Data Validation Helpers
// ============================================================================

/**
 * Validate date range
 */
export function validateDateRange(start: string, end: string): boolean {
  const startDate = new Date(start);
  const endDate = new Date(end);

  if (isNaN(startDate.getTime()) || isNaN(endDate.getTime())) {
    return false;
  }

  return startDate <= endDate;
}

/**
 * Check if data is empty
 */
export function isDataEmpty<T>(data: T[]): boolean {
  return !data || data.length === 0;
}

/**
 * Get max value from data
 */
export function getMaxValue<T extends { count: number }>(data: T[]): number {
  if (isDataEmpty(data)) return 0;
  return Math.max(...data.map((item) => item.count));
}

/**
 * Get min value from data
 */
export function getMinValue<T extends { count: number }>(data: T[]): number {
  if (isDataEmpty(data)) return 0;
  return Math.min(...data.map((item) => item.count));
}

/**
 * Error handling utilities for DoctorDashboard
 */

export interface FieldError {
  field: string;
  message: string;
}

export interface ValidationResult {
  isValid: boolean;
  errors: FieldError[];
}

/**
 * Validates diagnosis form fields
 */
export const validateDiagnosisForm = (data: {
  diagnosisName: string;
  diagnosisCode?: string;
  diagnosisNotes?: string;
  severity: string;
  fitnessDecision: string;
  advisedRestDays: number;
  workRestrictions?: string;
  followUpDate?: string;
  requiresReferral: boolean;
}): ValidationResult => {
  const errors: FieldError[] = [];

  // Diagnosis name validation
  if (!data.diagnosisName.trim()) {
    errors.push({ field: 'diagnosisName', message: 'Diagnosis name is required' });
  } else if (data.diagnosisName.length > 255) {
    errors.push({ field: 'diagnosisName', message: 'Diagnosis name cannot exceed 255 characters' });
  }

  // Diagnosis code validation (if provided)
  if (data.diagnosisCode && data.diagnosisCode.length > 50) {
    errors.push({ field: 'diagnosisCode', message: 'Diagnosis code cannot exceed 50 characters' });
  }

  // Diagnosis notes validation (if provided)
  if (data.diagnosisNotes && data.diagnosisNotes.length > 1000) {
    errors.push({ field: 'diagnosisNotes', message: 'Diagnosis notes cannot exceed 1000 characters' });
  }

  // Severity validation
  const validSeverities = ['MILD', 'MODERATE', 'SERIOUS', 'CRITICAL'];
  if (!validSeverities.includes(data.severity)) {
    errors.push({ field: 'severity', message: 'Invalid severity level' });
  }

  // Fitness decision validation
  const validDecisions = ['FIT', 'FIT_WITH_RESTRICTION', 'TEMPORARY_UNFIT', 'UNFIT'];
  if (!validDecisions.includes(data.fitnessDecision)) {
    errors.push({ field: 'fitnessDecision', message: 'Invalid fitness decision' });
  }

  // Advised rest days validation
  if (data.advisedRestDays < 0) {
    errors.push({ field: 'advisedRestDays', message: 'Advised rest days cannot be negative' });
  }
  if (data.advisedRestDays > 365) {
    errors.push({ field: 'advisedRestDays', message: 'Advised rest days cannot exceed 365' });
  }

  // Work restrictions validation (if provided)
  if (data.workRestrictions && data.workRestrictions.length > 500) {
    errors.push({ field: 'workRestrictions', message: 'Work restrictions cannot exceed 500 characters' });
  }

  // Follow-up date validation (if provided)
  if (data.followUpDate) {
    const followUpDate = new Date(data.followUpDate);
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    if (followUpDate < today) {
      errors.push({ field: 'followUpDate', message: 'Follow-up date cannot be in the past' });
    }
  }

  return {
    isValid: errors.length === 0,
    errors,
  };
};

/**
 * Validates prescription fields
 */
export const validatePrescription = (prescription: {
  medicine_name: string;
  dosage: string;
  frequency: string;
  duration_days: number;
  route?: string;
  instructions?: string;
}): ValidationResult => {
  const errors: FieldError[] = [];

  // Medicine name validation
  if (!prescription.medicine_name.trim()) {
    errors.push({ field: 'medicine_name', message: 'Medicine name is required' });
  } else if (prescription.medicine_name.length > 255) {
    errors.push({ field: 'medicine_name', message: 'Medicine name cannot exceed 255 characters' });
  }

  // Dosage validation
  if (!prescription.dosage.trim()) {
    errors.push({ field: 'dosage', message: 'Dosage is required' });
  } else if (prescription.dosage.length > 100) {
    errors.push({ field: 'dosage', message: 'Dosage cannot exceed 100 characters' });
  }

  // Frequency validation
  if (!prescription.frequency.trim()) {
    errors.push({ field: 'frequency', message: 'Frequency is required' });
  } else if (prescription.frequency.length > 100) {
    errors.push({ field: 'frequency', message: 'Frequency cannot exceed 100 characters' });
  }

  // Duration days validation
  if (prescription.duration_days <= 0) {
    errors.push({ field: 'duration_days', message: 'Duration must be at least 1 day' });
  }
  if (prescription.duration_days > 365) {
    errors.push({ field: 'duration_days', message: 'Duration cannot exceed 365 days' });
  }

  // Route validation (if provided)
  if (prescription.route && prescription.route.length > 50) {
    errors.push({ field: 'route', message: 'Route cannot exceed 50 characters' });
  }

  // Instructions validation (if provided)
  if (prescription.instructions && prescription.instructions.length > 500) {
    errors.push({ field: 'instructions', message: 'Instructions cannot exceed 500 characters' });
  }

  return {
    isValid: errors.length === 0,
    errors,
  };
};

/**
 * Validates all prescriptions in an array
 */
export const validatePrescriptions = (
  prescriptions: Array<{
    medicine_name: string;
    dosage: string;
    frequency: string;
    duration_days: number;
    route?: string;
    instructions?: string;
  }>
): ValidationResult => {
  const errors: FieldError[] = [];

  // Check if at least one prescription is filled
  const filledPrescriptions = prescriptions.filter(p => p.medicine_name.trim() !== '');

  if (filledPrescriptions.length === 0) {
    errors.push({ field: 'prescriptions', message: 'At least one prescription is required' });
    return {
      isValid: false,
      errors,
    };
  }

  // Validate each prescription
  prescriptions.forEach((prescription, index) => {
    if (prescription.medicine_name.trim()) {
      const result = validatePrescription(prescription);
      result.errors.forEach(err => {
        errors.push({
          field: err.field,
          message: `Prescription ${index + 1}: ${err.message}`,
        });
      });
    }
  });

  return {
    isValid: errors.length === 0,
    errors,
  };
};

/**
 * Formats API error for display
 */
export const formatSubmitError = (error: unknown): string => {
  if (typeof error === 'string') {
    return error;
  }

  if (error instanceof Error) {
    return error.message;
  }

  if (error && typeof error === 'object' && 'detail' in error) {
    const detail = (error as any).detail;
    if (Array.isArray(detail)) {
      return detail.join(', ');
    }
    return String(detail);
  }

  return 'Failed to submit diagnosis. Please try again.';
};

/**
 * Gets the first error message for a specific field
 */
export const getFieldError = (
  errors: FieldError[],
  fieldName: string
): string | undefined => {
  return errors.find(e => e.field === fieldName)?.message;
};

/**
 * Gets all errors (useful for form display)
 */
export const getAllErrors = (errors: FieldError[]): Record<string, string> => {
  return errors.reduce((acc, err) => {
    acc[err.field] = err.message;
    return acc;
  }, {} as Record<string, string>);
};
